import{_ as l,o as t,c as r,a4 as n}from"./chunks/framework.EYT3XhWU.js";const _=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"行测/言语理解/逻辑填空/词语积累.md","filePath":"行测/言语理解/逻辑填空/词语积累.md"}'),s={name:"行测/言语理解/逻辑填空/词语积累.md"};function i(g,o,e,c,d,p){return t(),r("div",null,[...o[0]||(o[0]=[n('<h2 id="一、成语辨析" tabindex="-1">一、成语辨析 <a class="header-anchor" href="#一、成语辨析" aria-label="Permalink to “一、成语辨析”">​</a></h2><ol><li><p><strong>1、稳扎稳打 有条不紊 循序渐进</strong></p><ol><li><strong>[稳扎稳打]</strong>：比喻有把握、有步骤地工作。<code>强调把握</code></li><li><strong>[有条不紊]</strong>：形容有条理，一点不乱。<code>强调条理</code></li><li><strong>[循序渐进]</strong>：指学习工作等按一定的步骤逐渐深入或提高。<code>强调一步步由浅入深</code></li></ol></li><li><p><strong>2、有的放矢 因地制宜 对症下药 量体裁衣</strong></p><ol><li><strong>[有的放矢]</strong>：放箭要对准靶子。比喻说话做事有针对性。<code>有针对性、有目的。褒义。</code></li><li><strong>[因地制宜]</strong>：根据各地的具体情况，制定适宜的办法。<code>具体情况具体分析。褒义。作谓语、宾语、状语</code></li><li><strong>[对症下药]</strong>：针对病症用药。比喻针对事物的问题所在，采取有效的措施。<code>找准问题，措施有效。褒义。作谓语、定语、状语</code></li><li><strong>[量体裁衣]</strong>：按照身材裁剪衣服。比喻按照实际情况办事。<code>办实事。作谓语、宾语、分句</code></li></ol></li><li><p><strong>3、脚踏实地 按部就班 循序渐进 步步为营 按图索骥</strong></p><ol><li><strong>[脚踏实地]</strong>：比喻做事踏实，认真。<code>褒义，多用在工作、治学、为人上</code></li><li><strong>[按部就班]</strong>：按照一定的步骤、顺序进行。也指按老规矩办事，缺乏创新精神。<code>中性词，按老规矩办事，作谓语、状语，有时作定语</code></li><li><strong>[循序渐进]</strong>：指学习工作等按照一定的步骤逐渐深入或提高。<code>褒义，逐渐深入或提高</code></li><li><strong>[步步为营]</strong>：军队每向前推进一步就设下一个营垒。形容防守严密，行动谨慎。<code>中性词，作谓语、宾语</code></li><li><strong>[按图索骥]</strong>：按照图像去寻找好马。比喻办事机械、死板，不知变通。后也比喻依照一定的线索去寻找事物。常做中性词或贬义词。不能直接认定他就是贬义的！</li></ol></li><li><p><strong>4.不知所措 无所适从 莫衷一是 一筹莫展</strong></p><ol><li><strong>[不知所措]</strong>：指不知道怎么办才好，形容处境为难或心神慌乱。动宾式结构；在句中一般作谓语、状语、补语。<code>强调毫无行动方案</code></li><li><strong>[一筹莫展]</strong>：一点计策也施展不出，一点办法也想不出来。<code>没有法子</code></li><li><strong>[无所适从]</strong>：不知道听谁的才好；不知道按哪个办法做才对。<code>强调虽有行动方案，但难以决定</code></li><li><strong>[莫衷一是]</strong>：形容意见分歧，没有一致的看法。<code>强调意见分歧</code></li></ol></li><li><p><strong>5、抱薪救火 饮鸩止渴 缘木求鱼 焚林而猎 扬汤止沸 削足适履 因噎废食</strong></p><ol><li><strong>[抱薪救火]</strong>：比喻用错误的方法去消除灾祸，结果使灾祸反而扩大。<code>惹了祸事，自讨苦吃</code></li><li><strong>[饮鸩止渴]</strong>：比喻用错误的办法来解决眼前的困难而不顾严重后果。<code>方法错误，不计后果</code></li><li><strong>[缘木求鱼]</strong>：比喻方向或办法不对头，不可能达到目的。<code>方法不当，难达目的</code></li><li><strong>[焚林而猎]</strong>：比喻只图眼前利益，不作长久打算。<code>只图眼前利益，同“杀鸡取卵”</code></li><li><strong>[扬汤止沸]</strong>：把沸水舀起来再倒回去，以图阻止住沸腾。比喻不成功的补救办法，办法不彻底，不能从根本上解决问题<code>强调治标不治本</code></li><li><strong>[削足适履]</strong>：为了将大脚塞进小鞋而把脚削小。喻指不根据实际情况而盲目套用。<code>强调盲目迁就，不顾实际</code></li><li><strong>[因噎废食]</strong>：比喻要做的事情由于出了点小毛病或怕出问题就索性不去干。<code>强调极端。含贬义。作谓语、定语、宾语。</code></li></ol></li><li><p><strong>6、一蹴而就 一挥而就 一劳永逸 一步到位 一步登天</strong></p><ol><li><strong>[一蹴而就]</strong>：踏一步就成功。比喻事情轻而易举，一下子就成功。<code>一下子就成功，多用作贬义</code></li><li><strong>[一挥而就]</strong>：动笔就写成了形容写字、写文章、画画快。褒义。</li><li><strong>[一劳永逸]</strong>：辛苦一次，把事情办好，以后就可以不再费力了。<code>褒义，多用在否定句中</code></li><li><strong>[一步到位]</strong>：指一次就能达到预定的目标。</li><li><strong>[一步登天]</strong>：比喻一下子就达到很高的境界或程度。有时也用来比喻人突然得志，爬上高位。<code>人突然得志，含有嘲讽意味</code></li></ol></li><li><p><strong>7、捉襟见肘 左支右绌 顾此失彼</strong></p><ol><li><strong>[捉襟见肘]</strong>：形容衣服破烂。比喻穷于应付。在现代汉语中，捉襟见肘可比喻成资金、物质条件，以及能力上的匮乏或欠缺，有时还指某件事物的不完善。<code>资金、物质条件或能力匮乏</code></li><li><strong>[左支右绌]</strong>：指力量不足，应付了这方面，那方面又出了问题。<code>力量不足，总出问题</code></li><li><strong>[顾此失彼]</strong>：顾了这个，丢了那个。形容忙乱或慌张的情境。<code>无法统筹兼顾平衡</code></li></ol></li><li><p><strong>8、抱残守缺 墨守成规 故步自封 因循守旧</strong></p><ol><li><strong>[抱残守缺]</strong>：抱着残缺陈旧的东西不放。形容思想保守，不求改进。<code>不改进</code></li><li><strong>[墨守成规]</strong>：指思想保守，守着老规矩不放。<code>不变通</code></li><li><strong>[故步自封]</strong>：比喻守着老一套，不求进步。<code>不思进取</code></li><li><strong>[因循守旧]</strong>：死守老一套，缺乏创新精神。<code>不创新</code></li></ol></li><li><p><strong>9、南辕北辙 大相径庭 缘木求鱼 刻舟求剑</strong></p><ol><li><strong>[南辕北辙]</strong>：意思是心想往南而车子却向北行。比喻行动和目的相抵触。<code>行动和目的相反，通常用在同一主体身上</code></li><li><strong>[缘木求鱼]</strong>：比喻方向、方法不对，不可能达到目的。<code>行动的方法错了</code></li><li><strong>[大相径庭]</strong>：比喻彼此差别很大，极为不同。<code>差别大</code></li><li><strong>[刻舟求剑]</strong>：比喻不懂事物已发展变化而仍静止地看问题。<code>做事不知进退，不按客观变化办事。作谓语、定语、状语</code></li></ol></li><li><p><strong>10、别出心裁 别具一格 独辟蹊径 独树一帜 标新立异</strong></p><ol><li><strong>[别出心裁]</strong>：另有一种构思或设计。指想出的办法与众不同。<code>办法</code></li><li><strong>[独辟蹊径]</strong>：比喻独创一种风格或新的方法。<code>风格或方法</code></li><li><strong>[别具一格]</strong>：另有一种独特的风格。<code>风格</code></li><li><strong>[独树一帜]</strong>：比喻独特新奇，自成一家。<code>思想</code></li><li><strong>[标新立异]</strong>：提出新奇的主张，表示与众不同。<code>主张</code></li></ol></li><li><p><strong>11、独善其身 明哲保身 画地为牢 袖手旁观</strong></p><ol><li><strong>[独善其身]</strong>：原意是做不上官就修养好自身。现指只顾自己，不管别人。</li><li><strong>[明哲保身]</strong>：明智的人善于保全自己。现指因怕连累自己而回避斗争的处世态度。</li><li><strong>[画地为牢]</strong>：比喻只许在指定的范围内活动。<code>不逾越</code></li><li><strong>[袖手旁观]</strong>：比喻置身事外，既不过问，也不协助别人。<code>不过问，不协助，含贬义</code></li></ol></li><li><p><strong>12、随波逐流 人云亦云</strong></p><ol><li><strong>[随波逐流]</strong>：比喻没有坚定的立场，缺乏判断是非的能力，只能跟着别人走。<code>侧重于行动</code></li><li><strong>[人云亦云]</strong>：人家怎么说，自己也怎么说。指没有主见，只会随声附和。<code>侧重在说</code></li></ol></li><li><p><strong>13、举一反三 触类旁通 融会贯通</strong></p><ol><li><strong>[举一反三]</strong>：举一个例子便能够推知其他的。<code>侧重于理解知识。</code></li><li><strong>[触类旁通]</strong>：指掌握了某一事物的知识或规律，进而推知同类事物的知识或规律。<code>侧重于掌握知识和技能</code></li><li><strong>[融会贯通]</strong>：把各方面的知识和道理融化汇合，得到全面透彻的理解。<code>用于学习方面，强调知识融合汇合</code></li></ol></li><li><p><strong>14、审时度势 因势利导 度德量力</strong></p><ol><li><strong>[审时度势]</strong>：观察分析时势，估计情况的变化。<code>洞察形势。褒义。作谓语、宾语</code></li><li><strong>[因势利导]</strong>：顺着事情发展的趋势，加以引导。<code>顺势引导。作谓语、定语、状语</code></li><li><strong>[度德量力]</strong>：衡量自己的德行是否能够服人，估计自己的能力是否能够胜任。<code>自我掂量。作谓语</code></li></ol></li><li><p><strong>15、顺水推舟 因势利导</strong></p><ol><li><strong>[顺水推舟]</strong>：顺著水流的方向推船。比喻顺应情势行事。<code>强调已经行动</code></li><li><strong>[因势利导]</strong>：顺应事物发展的趋势而加以引导。<code>强调引导后才有后续行动</code></li></ol></li><li><p><strong>16、并行不悖 双管齐下 并驾齐驱</strong></p><ol><li><strong>[并行不悖]</strong>：同时进行，不相冲突。<code>不冲突，适用于物，多方面</code></li><li><strong>[双管齐下]</strong>：原指手握双笔同时作画。后比喻做一件事两个方面同时进行或两种方法同时使用。<code>两件事情同时进行，两方面</code></li><li><strong>[并驾齐驱]</strong>：并排套着的几匹马一齐快跑。比喻彼此的力量或才能不分高下。<code>悬殊不大，不分彼此。适用对象：人、其他事物。作谓语</code></li></ol></li><li><p><strong>17、独善其身 以邻为壑 自行其是</strong></p><ol><li><strong>[独善其身]</strong>：比喻只顾自己，不管别人的个人主义的处世哲学。含贬义。</li><li><strong>[以邻为壑]</strong>：拿邻国当做大水坑，把本国的洪水排泄到那里去。比喻只图自己一方的利益，把困难或祸害转嫁给别人。<code>自私自利，祸害别人</code></li><li><strong>[自行其是]</strong>：自己认为对的就做，不考虑别人的意见。<code>作谓、定语。含贬义</code></li></ol></li><li><p><strong>18、掩耳盗铃 买椟还珠 削足适履 寅吃卯粮</strong></p><ol><li><strong>[掩耳盗铃]</strong>：比喻自己欺骗自己，明明掩盖不住的事情偏要想法子掩盖。<code>自欺欺人</code></li><li><strong>[买椟还珠]</strong>：买下木匣，退还了珍珠。比喻没有眼力，取舍不当。<code>不识货，取舍不当</code></li><li><strong>[寅吃卯粮]</strong>：这一年吃了下一年的粮。比喻经济困难，收入不够支出，预先支用了以后的进项。比喻指经济困难，入不敷出。<code>透支，入不敷出</code></li></ol></li><li><p><strong>19、生搬硬套 移花接木</strong></p><ol><li><strong>[生搬硬套]</strong>：指不顾实际情况，机械地运用别人的经验，照抄别人的办法。<code>机械照抄。贬义</code></li><li><strong>[移花接木]</strong>：把一种花木的枝条或嫩芽嫁接在另一种花木上。比喻暗中用手段更换人或事物来欺骗别人。<code>更换或拼凑欺骗人。作谓语、定语</code></li></ol></li><li><p><strong>20、半途而废 浅尝辄止</strong></p><ol><li><strong>[半途而废]</strong>：指做事不能坚持到底，中途停顿，有始无终。<code>途中放弃</code></li><li><strong>[浅尝辄止]</strong>：略微尝试一下就停下来。指不深入钻研。<code>不深入</code></li></ol></li><li><p><strong>21、身先士卒 以身作则 一马当先</strong></p><ol><li><strong>[身先士卒]</strong>：作战时将领亲自带头，冲在士兵前面。现在也比喻领导带头，走在群众前面。</li><li><strong>[以身作则]</strong>：以自己的行动做出表率。</li><li><strong>[一马当先]</strong>：形容领先。也比喻工作走在最前面。<code>侧重的做工作比较超前领先</code></li></ol></li><li><p><strong>22、前仆后继 前赴后继</strong></p><ol><li><strong>[前仆后继]</strong>：前面的倒下了，后面的紧跟上去。形容斗争英勇壮烈。<code>不怕牺牲</code></li><li><strong>[前赴后继]</strong>：前面的冲上去了，后面的紧跟上来。形容不断的投入战斗，奋勇冲杀向前。<code>不怕困难，奋勇向前</code></li></ol></li><li><p><strong>23、建言献策 出谋划策</strong></p><ol><li><strong>[建言献策]</strong>：陈述主张或意见。<code>不仅出主意，而且积极主张</code></li><li><strong>[出谋划策]</strong>：意思是制定计谋策略。多指为人出主意。<code>出主意</code></li></ol></li><li><p><strong>24、改过自新 痛改前非 脱胎换骨</strong></p><ol><li><strong>[改过自新]</strong>：改正错误，重新做起。<code>侧重自身的觉悟和主动改正</code></li><li><strong>[痛改前非]</strong>：彻底改正以前所犯的错误。<code>强调彻底、坚决的改正</code></li><li><strong>[脱胎换骨]</strong>：现比喻通过教育，思想得到彻底改造。<code>强调从思想、性格、行为到本质发生改变，程度最深</code></li></ol></li><li><p><strong>25、措手不及 猝不及防 防不胜防</strong></p><ol><li><strong>[措手不及]</strong>：指事出意外，一时无法对付。<code>强调对付</code></li><li><strong>[猝不及防]</strong>：事情来得突然，来不及防备。<code>强调突然</code></li><li><strong>[防不胜防]</strong>：形容防备不过来。 <code>强调防备</code></li></ol></li><li><p><strong>26、亦步亦趋 邯郸学步 东施效颦 步人后尘</strong></p><ol><li><strong>[亦步亦趋]</strong>：比喻由于缺乏主张，或为了讨好，事事模仿或追随别人。<code>侧重无主见</code></li><li><strong>[邯郸学步]</strong>：比喻模仿人不到家，反把自己原来会的东西忘了。<code>模仿丢了本</code></li><li><strong>[东施效颦]</strong>：比喻胡乱模仿，效果极坏。<code>模仿翻车了</code></li><li><strong>[步人后尘]</strong>：指跟在人家后面走。比喻追随模仿，学人家的样子，没有创造性。<code>缺乏创造性；走老路</code></li></ol></li><li><p><strong>27、踌躇不前 畏首畏尾 望而却步</strong></p><ol><li><strong>[踌躇不前]</strong>：犹豫不决，不敢前进。</li><li><strong>[畏首畏尾]</strong>：比喻做事胆子小，顾虑多。</li><li><strong>[望而却步]</strong>：形容事物可怕或讨厌，使人一看就往后退缩。</li></ol></li><li><p><strong>28、改头换面 洗心革面 判若两人</strong></p><ol><li><strong>[改头换面]</strong>：多比喻只改变外表和形式，内容实质不变。</li><li><strong>[洗心革面]</strong>：清除旧思想，改变旧面貌。比喻彻底悔改。<code>重新做人，思想上的悔改</code></li><li><strong>[判若两人]</strong>：形容某人前后的言行明显不一致，象两个人一样<code>你变了，以前的你不这样的</code></li></ol></li><li><p><strong>29、坐山观虎斗 袖手旁观 隔岸观火</strong></p><ol><li><strong>[坐山观虎斗]</strong>：比喻对双方的斗争采取旁观的态度，等到双方都受到损伤，再从中捞取好处。<code>有目的</code></li><li><strong>[袖手旁观]</strong>：比喻置身事外，既不过问，也不协助别人。<code>无目的</code></li><li><strong>[隔岸观火]</strong>：比喻对别人的危难不去求助，在一旁看热闹。<code>无目的</code></li></ol></li><li><p><strong>30、孤注一掷 破釜沉舟 釜底抽薪</strong></p><ol><li><strong>[孤注一掷]</strong>：比喻在危急时刻用尽所有力量作最后一次冒险。</li><li><strong>[破釜沉舟]</strong>：比喻下决心不顾一切地干到底。</li><li><strong>[釜底抽薪]</strong>：比喻从根本上解决问题。</li></ol></li><li><p><strong>31、千篇一律 规行矩步</strong></p><ol><li><strong>[千篇一律]</strong>：一千篇文章都一个样。指文章公式化。也比喻办事按一个格式，非常机械。<code>形式陈旧，办事机械。贬义</code></li><li>规行矩步]**：指严格按照规矩办事，毫不苟且。也指办事死板，不灵活。<code>照章办事；办事死板不灵活。多含贬义。</code></li></ol></li><li><p><strong>32、独断专行 一意孤行</strong></p><ol><li><strong>[独断专行]</strong>：行事专断，不考虑别人的意见。形容作风不民主。<code>不民主</code></li><li><strong>[一意孤行]</strong>：指不接受别人的劝告，顽固地按照自己的主观想法去做。<code>顽固</code></li></ol></li><li><p><strong>33、各行其是 各自为政 各司其职</strong></p><ol><li><strong>[各行其是]</strong>：按照各自认为对的去做。比喻各搞一套。<code>自主主张。贬义。作谓语、宾语</code></li><li><strong>[各自为政]</strong>：各自行使各自的政令。比喻步调不一致，各行其是。<code>没有集体主义精神。作谓语。</code></li><li><strong>[各司其职]</strong>：每个人尽自己的职责，做好所承担的工作。<code>做好分内事。褒义。</code></li></ol></li><li><p><strong>34、越俎代庖 李代桃僵 火中取栗 鸠占鹊巢</strong></p><ol><li><strong>[越俎代庖]</strong>：比喻超出自己业务范围去处理别人所管的事。<code>越权办事，狗拿耗子</code></li><li><strong>[李代桃僵]</strong>：原比喻兄弟互相爱护和帮助，后比喻以此代彼或代人受过。<code>代人受过</code></li><li><strong>[火中取栗]</strong>：偷取炉中烤熟的栗子。比喻受人利用，冒险出力却一无所得。<code>被人利用无所获。作谓语、定语</code></li><li><strong>[鸠占鹊巢]</strong>：指强站别人的住屋，土地，产业等。<code>强占他人的产业</code></li></ol></li><li><p><strong>35、高枕无忧 作壁上观</strong></p><ol><li><strong>[高枕无忧]</strong>：平安无事，无所顾虑，也形容缺乏警觉性。<code>适用语境：多用于劝告、指责或批评。一般作谓语、状语。</code></li><li><strong>[作壁上观]</strong>：原指双方交战，自己站在壁垒上旁观。后多比喻站在一旁看着，不动手帮助。<code>干愣着，不帮助</code></li></ol></li><li><p><strong>36、捕风捉影 道听途说</strong></p><ol><li><strong>[捕风捉影]</strong>：比喻说话做事丝毫没有事实根据。</li><li><strong>[道听途说]</strong>：泛指没有根据的传闻。</li></ol></li><li><p><strong>37、无孔不入 见缝插针</strong></p><ol><li><strong>[无孔不入]</strong>：比喻消极的东西易于渗透、侵入。亦指人善于钻营，有隙就乘机营求<code>含贬义。适用对象：人、事、思想、感情等方面。作谓语、定语、状语</code></li><li><strong>[见缝插针]</strong>：比喻尽可能利用一切可以利用的空间或时间。<code>褒义。常用于抓紧时间和充分利用空间方面。一般作定语、状语。</code></li></ol></li><li><p><strong>38、正本清源 标本兼治 釜底抽薪</strong></p><ol><li><strong>[正本清源]</strong>：从根本上整顿，从源头上清理。比喻从根本上加以整顿清理。<code>从根本上清理整顿</code></li><li><strong>[标本兼治]</strong>：治标又治本。表面和内在兼顾。</li><li><strong>[釜底抽薪]</strong>：比喻从根本上解决问题。<code>根本上解决问题</code></li></ol></li><li><p><strong>39、从善如流 择善而从 闻过则喜</strong></p><ol><li><strong>[从善如流]</strong>：形容能迅速地接受别人的好意见。<code>乐于接受他人意见，可作谓语、宾语、定语</code></li><li><strong>[择善而从]</strong>：指选择好的学，按照好的做。<code>向榜样学习，含褒义，可作谓语、宾语</code></li><li><strong>[闻过则喜]</strong>：听到别人批评自己的缺点或错误，表示欢迎和高兴。指虚心接受意见。<code>虚心接受意见，含褒义，可作谓语、定语</code></li></ol></li><li><p><strong>40、兼收并蓄 博采众长 集思广益</strong></p><ol><li><strong>[兼收并蓄]</strong>：把不同内容、不同性质的东西收下来，保存起来。<code>收藏容纳一切</code></li><li><strong>[博采众长]</strong>：广泛吸取各家的长处。<code>吸取一切好的，作谓语、定语</code></li><li><strong>[集思广益]</strong>：指集中群众的智慧，广泛吸收有益的意见。<code>吸取一切有益意见</code></li></ol></li><li><p><strong>41、量力而行 精打细算 量入为出</strong></p><ol><li><strong>[量力而行]</strong>：按照自己力量的大小去做，不要勉强。<code>用于做事的实事求是的态度，作谓语</code></li><li><strong>[精打细算]</strong>：精密地计划，详细地计算。指在使用人力物力时计算得很精细。<code>侧重于精细化，褒义</code></li><li><strong>[量入为出]</strong>：根据收入的多少来定开支的限度。<code>强调收支平衡，作谓语、定语</code></li></ol></li><li><p><strong>42、严阵以待 严防死守 防微杜渐</strong></p><ol><li><strong>[严阵以待]</strong>：指做好充分战斗准备，等待着敌人。<code>备战，战斗前的场面，作谓语、定语</code></li><li><strong>[严防死守]</strong>：严密防护，坚决死守，表示非常坚定守住的意思。<code>防卫守卫状态，已在战斗</code></li><li><strong>[防微杜渐]</strong>：比喻在坏事情坏思想萌芽的时候就加以制止，不让它发展。<code>制止坏事的苗头，多用在表目的的动词或介词之后</code></li></ol></li><li><p><strong>43、面面俱到 八面玲珑 左右逢源</strong></p><ol><li><strong>[面面俱到]</strong>：各方面都能照顾到，没有遗漏疏忽。也指虽然照顾到各方面，但一般化。<code>应付很全面，事无巨细。中性词</code></li><li><strong>[八面玲珑]</strong>：后用来形容人处世圆滑，待人接物面面俱到。<code>谁也不得罪。含贬义，有讽刺意味</code></li><li><strong>[左右逢源]</strong>：原指赏识广博，应付裕如。后也比喻做事得心应手，非常顺利。<code>现在常用作贬义；比喻人办事圆滑。一般作谓语、状语、补语。</code></li></ol></li><li><p><strong>44、巧言令色 察言观色 趋炎附势 曲意逢迎</strong></p><ol><li><strong>[巧言令色]</strong>：指用花言巧语和媚态伪情来迷惑、取悦他人。<code>取悦人</code></li><li><strong>[察言观色]</strong>：观察言语脸色，以揣度对方的心意。<code>揣度人</code></li><li><strong>[趋炎附势]</strong>：炎：比喻有权势的人。指奉承依附有权有势的人。<code>奉承人</code></li><li><strong>[曲意逢迎]</strong>：违反自己的本心去迎合别人的意思。<code>迎合人</code></li></ol></li><li><p><strong>45、纵横捭阖 经天纬地</strong></p><ol><li><strong>[纵横捭阖]</strong>：指在政治或外交上运用手段进行分化或拉拢。<code>政治外交上分化或拉拢，适用语境：政治斗争。作谓语、定语</code></li><li><strong>[经天纬地]</strong>：规划天地。形容人的才能极大，能做非常伟大的事业。<code>有才能，能干大事业，含褒义，作谓语、定语</code></li></ol></li><li><p><strong>46、卷土重来 东山再起 死灰复燃 重振旗鼓</strong></p><ol><li><strong>[卷土重来]</strong>：比喻失败之后，重新恢复势力。<code>强调恢复力量</code></li><li><strong>[东山再起]</strong>：指再度出任要职。也比喻失势之后又重新得势。<code>强调再创辉煌</code></li><li><strong>[死灰复燃]</strong>：比喻已经消失了的恶势力或消亡的旧事物又重新活跃起来。<code>多指被打击过的不好的事物、风气有了苗头，比如黑恶势力、迷信活动、传销等</code></li><li><strong>[重振旗鼓]</strong>：比喻失败后，整顿再起。 <code>强调再战前的整顿</code></li></ol></li><li><p><strong>47、改邪归正 弃暗投明 金盆洗手 浪子回头</strong></p><ol><li><strong>[改邪归正]</strong>：从邪路上回到正路上来，不再做坏事</li><li><strong>[弃暗投明]</strong>：比喻在政治上脱离反动阵营，投向进步方面。</li><li><strong>[金盆洗手]</strong>：原指由给汉长安王宫送粮的船民，在渭河渡口上岸后举行的一个仪式，表示给官家的功业做完；后指某些黑道人物发财后准备安享晚年，公开宣布改邪归正；现也指放弃以前长期从事的行业或某件事。</li><li><strong>[浪子回头]</strong>：不务正业的人改邪归正。</li></ol></li><li><p><strong>48、坐享其成 坐收渔利 不劳而获 守株待兔</strong></p><ol><li><strong>[坐享其成]</strong>：自己不出力而享受别人取得的成果。<code>强调分享他人的成果，通俗点就是白嫖。含贬义，作谓语、宾语</code></li><li><strong>[坐收渔利]</strong>：比喻利用别人的矛盾而从中获利。<code>强调作为旁观者利用矛盾获利。含贬义，作谓语、宾语、定语</code></li><li><strong>[不劳而获]</strong>：自己不劳动却占有别人的劳动成果。<code>强调一种依赖式的占用，通俗地说就是等靠要，等着天上掉馅饼。含贬义，作谓语、定语、状语</code></li><li><strong>[守株待兔]</strong>：比喻死守经验，不知变通。亦用以讽刺妄想不劳而获的侥幸心理。<code>死守经验不变通；心存侥幸不努力。含贬义，有时也可用作褒义，如民警守株待兔抓盗贼</code></li></ol></li><li><p><strong>49、唯命是从 奉为圭臬 百依百顺</strong></p><ol><li><strong>[唯命是从]</strong>：是命令式服从，不敢半点违抗。<code>多用于上下级之间，贬义</code></li><li><strong>[奉为圭<code>guī</code>臬<code>niè</code>]</strong>：圭臬：比喻事物的准则。比喻把某些言论或事当成自己的准则。<code>指十分信奉某些事物或言论；当作依据的标准。中性词。一般作谓语。</code></li><li><strong>[百依百顺]</strong>：什么都依从。形容一切都顺从别人。<code>强调感情上的爱而表现出来的顺从</code></li></ol></li><li><p><strong>50、照本宣科 敷衍了事 偷工减料</strong></p><ol><li><strong>[照本宣科]</strong>：照着本子念条文。形容讲课、发言等死板地按照课文、讲稿，没有发挥，不生动。<code>死板无创新，作谓语、定语、状语</code></li><li><strong>[敷衍了事]</strong>：指办事马马虎虎，只求应付过去就算完事。<code>办事马虎，应付</code></li><li><strong>[偷工减料]</strong>：原指商人为了牟取暴利而暗中降低产品质量，削减工料。现也指做事图省事，马虎敷衍。<code>图省事</code></li></ol></li><li><p><strong>50、挥金如土 一掷千金 堆金积玉</strong></p><ol><li><strong>[挥金如土]</strong>：把钱财当成泥土一样挥霍。形容极端挥霍浪费。<code>挥霍浪费</code></li><li><strong>[一掷千金]</strong>：指用钱满不在乎，一花就是一大笔。<code>花钱大度阔绰</code></li><li><strong>[堆金积玉]</strong>：金玉多得可以堆积起来。今指占有的财富极多。</li></ol></li><li><p><strong>52、乘人之危 落井下石</strong></p><ol><li><strong>[乘人之危]</strong>：乘人家危难的时候去威胁损害。<code>逮着机会整你</code></li><li><strong>[落井下石]</strong>：比喻乘人有危难时加以陷害。<code>逮着机会往死里整你</code></li></ol></li><li><p><strong>53、浑水摸鱼 趁火打劫</strong></p><ol><li><strong>[浑水摸鱼]</strong>：比喻乘混乱的时候从中捞取利益。<code>适用情境：混乱或者人为制造混乱</code></li><li><strong>[趁火打劫]</strong>：比喻乘人之危谋取私利。<code>适用情境：紧张、危急或困难的时候</code></li></ol></li><li><p><strong>54、暗箭伤人 含沙射影</strong></p><ol><li><strong>[暗箭伤人]</strong>：比喻暗地里用某种手段伤害人。<code>贬义，用语言、文字、行动伤害人</code></li><li><strong>[含沙射影]</strong>：比喻暗中攻击或陷害人。<code>贬义，诽谤陷害</code></li></ol></li><li><p><strong>55、耳熟能详 妇孺皆知 如数家珍</strong></p><ol><li><strong>[耳熟能详]</strong>：指听得多了，能够说得很清楚、很详细。<code>听得多了，知道得详细，有信息来源</code></li><li><strong>[妇孺皆知]</strong>：老人小孩都知道。指众所周知。<code>知道的人多，只有结果，无信息来源</code></li><li><strong>[如数家珍]</strong>：好像数自己家藏的珍宝那样清楚。比喻对所讲的事情十分熟悉。<code>指代的只能是别人的东西</code></li></ol></li><li><p><strong>56、崭露头角 初露锋芒 脱颖而出</strong></p><ol><li><strong>[崭露头角]</strong>：比喻突出地显露出才能和本领。</li><li><strong>[初露锋芒]</strong>：刚显露出某种力量或才能。</li><li><strong>[脱颖而出]</strong>：比喻人的才能全部显示出来。</li></ol></li><li><p><strong>57、不谋而合 如出一辙 无独有偶 殊途同归</strong></p><ol><li><strong>[不谋而合]</strong>：事前没有商量过而彼此意见或行动却完全一致。<code>事前无预判</code></li><li><strong>[如出一辙]</strong>：像出自同一个车辙。比如两件事非常相似。<code>结果本身的存在预判</code></li><li><strong>[无独有偶]</strong>：表示两事或两人十分相似。<code>强调一种坏事不止一件的惊诧。多用于贬义</code></li><li><strong>[殊途同归]</strong>：比喻采取不同的方法而得到相同的结果。<code>适用对象：道路和学习、工作、艺术、外交等方面。作谓语、宾语、定语</code></li></ol></li><li><p><strong>58、泾渭分明 大相径庭 截然相反 迥然不同 天差地别 天壤之别 云泥之别 相去甚远 背道而驰</strong></p><ol><li><strong>[泾渭分明]</strong>：泾、渭二水，一清一浊，虽合流汇聚，却清浊分明。比喻是非明了，境界清楚<code>界限清楚</code></li><li><strong>[大相径庭]</strong>：比喻彼此差别很大，极为不同<code>强调差别很大</code></li><li><strong>[截然相反]</strong>：截然：界限分明。相反：完全相反的意思。<code>没有共同之处</code></li><li><strong>[迥然不同]</strong>：完全不同，相差很远。<code>强调不同，相似率0%</code></li><li><strong>[天差地别]</strong>：形容差别很大，相差甚远。<code>强调差别很大</code></li><li><strong>[天壤之别]</strong>：天和地，一极在上，一级在下，比喻差别极大。<code>好与坏无法相比或两个事物之间的差别极大。作宾语</code></li><li><strong>[云泥之别]</strong>：象天上的云和地上的泥那样高下不同。比喻地位的高下相差极大。<code>地位悬殊大。作宾语</code></li><li><strong>[相去甚远]</strong>：互相之间存在很大差异和距离。<code>强调差别和差距</code></li><li><strong>[背道而驰]</strong>：朝着相反方向的道路奔跑。比喻彼此方向目标完全相反<code>强调目标与初心相违背</code></li></ol></li><li><p><strong>59、望尘莫及 鞭长莫及 望洋兴叹 望其项背</strong></p><ol><li><strong>[望尘莫及]</strong>：只望见走在前面的人带起尘土而追赶不上。比喻远远落后。多用于表示对人钦佩的自谦语。<code>仅强调远远落后，自谦，在句子中作谓语</code></li><li><strong>[鞭长莫及]</strong>：原意是鞭子虽长，也不能到打马肚子。比喻相隔太远，力量达不到。<code>虽然努力依然达不到</code></li><li><strong>[望洋兴叹]</strong>：仰望海神而兴叹。原指在伟大事物面前感叹自己的渺小。现多比喻做事时因力不胜任或没有条件而感到无可奈何。<code>臣妾做不到啊!强调无奈</code></li><li><strong>[望其项背]</strong>：比喻赶得上。 <code>做得到，能够企及</code></li></ol></li><li><p><strong>60、举重若轻 举足轻重 无足轻重 避重就轻</strong></p><ol><li><strong>[举重若轻]</strong>：比喻能力强，能够轻松地胜任繁重的工作或处理困难的问题。<code>soesay!</code></li><li><strong>[举足轻重]</strong>：指处于重要地位，一举一动都足以影响全局。<code>很重要</code></li><li><strong>[无足轻重]</strong>：没有它并不轻些，有它也并不重些。指无关紧要。<code>不重要</code></li><li><strong>[避重就轻]</strong>：指回避重的责任，只拣轻的来承担。也指回避要点，只谈无关紧要的事情。<code>回避责任</code></li></ol></li><li><p><strong>61、积重难返 根深蒂固 坚如磐石 固若金汤</strong></p><ol><li><strong>[积重难返]</strong>：过长时间形成的思想作风或习惯，很难改变。<code>强调思想习惯难改变</code></li><li><strong>[根深蒂固]</strong>：比喻基础深厚，不容易动摇。<code>强调观念、传统不动摇</code></li><li><strong>[坚如磐石]</strong>：比喻不可动摇。<code>强调意志不动摇</code></li><li><strong>[固若金汤]</strong>：形容工事无比坚固。<code>坚固</code></li></ol></li><li><p><strong>62、泥沙俱下 鱼目混珠 鱼龙混杂 良莠不齐 参差不齐 滥竽充数</strong></p><ol><li><strong>[泥沙俱下]</strong>：比喻好坏不同的人或事物混杂在一起，一同显现出来。<code>好坏同时显现</code></li><li><strong>[鱼目混珠]</strong>：比喻用假的冒充真的。<code>以假乱真</code></li><li><strong>[鱼龙混杂]</strong>：比喻好的和坏的混在一起。<code>好坏都有</code></li><li><strong>[良莠不齐]</strong>：好人坏人都有，混在在一起。<code>侧重于品质，不能用于形容水平、成绩</code></li><li><strong>[参差不齐]</strong>：形容水平不一或很不整齐。</li><li><strong>[滥竽充数]</strong>：比喻无本领的冒充有本领，次货冒充好货。<code>适用范围：人和物，好次问题</code></li></ol></li><li><p><strong>63、得天独厚 与生俱来</strong></p><ol><li><strong>[得天独厚]</strong>：独具特殊优越的条件，也指所处的环境特别好。<code>环境因素</code></li><li><strong>[与生俱来]</strong>：从一出生就有。<code>自身因素</code></li></ol></li><li><p><strong>64、本末倒置 舍本逐末 得不偿失</strong></p><ol><li><strong>[本末倒置]</strong>：比喻把主次、轻重的位置弄颠倒了。<code>矛盾两方面的主次先后关系处理不当</code></li><li><strong>[舍本逐末]</strong>：比喻不抓根本环节，而只在枝节问题上下功夫。<code>矛盾的主要方面被舍弃，只追求次要的</code></li><li><strong>[得不偿失]</strong>：所得的利益抵偿不了所受的损失。<code>利益权衡问题</code></li></ol></li><li><p><strong>65、视而不见 熟视无睹 不屑一顾 置若罔闻</strong></p><ol><li><strong>[视而不见]</strong>：指不注意，不重视，睁着眼却没看见。也指不理睬，看见了当作没看见。<code>全当没看见，贬义，作谓语、定语</code></li><li><strong>[熟视无睹]</strong>：看惯了就象没看见一样。也指看到某种现象，但不关心，只当没有看见。<code>看惯了但并不关心，贬义，作谓语、定语</code></li><li><strong>[不屑一顾]</strong>：认为不值得一看。形容极端轻视。<code>用于形容藐视、轻视，作谓语、定语</code></li><li><strong>[置若罔闻]</strong>：放在一边，好像没有听见似的。指不予理睬。<code>多用于批评、指责别人的场合，贬义，作谓语、宾语</code></li></ol></li><li><p><strong>66、无可厚非 毋庸置疑 无可非议</strong></p><ol><li><strong>[无可厚非]</strong>：不能过分责备。指说话做事虽有缺点，但还有可取之处，应予谅解。<code>不必过分责备。多用来表示虽有缺点，无伤大体，可以原谅。作谓语</code></li><li><strong>[毋庸置疑]</strong>：不必怀疑。 <code>适用语境：事实明显或理由充分</code></li><li><strong>[无可非议]</strong>：没有什么可以指责的。表示做得妥当。<code>做的好，没毛病。适用对象：可用来形容人、事、思想、行动、品质等。作主语、宾语。</code></li></ol></li><li><p><strong>67、异曲同工 大同小异 殊途同归</strong></p><ol><li><strong>[异曲同工]</strong>：不同的曲调演得同样好。比喻话的说法不一而用意相同，或一件事情的做法不同而都巧妙地达到目的。<code>表面虽不同而本质相同。含褒义。作定语、宾语</code></li><li><strong>[大同小异]</strong>：大体相同，略有差异。<code>差不多一样。适用语境：用于比较人或事物差别不大时。作谓语</code></li><li><strong>[殊途同归]</strong>：比喻采取不同的方法而得到相同的结果。</li></ol></li><li><p><strong>68、独占鳌头 独当一面 独领风骚</strong></p><ol><li><strong>[独占鳌头]</strong>：科举时代指点状元。比喻占首位或第一名。<code>第一名。褒义。作谓语、定语。</code></li><li><strong>[独当一面]</strong>：单独负责一个方面的工作。<code>能胜任某方面工作。作谓语、定语、状语</code></li><li><strong>[独领风骚]</strong>：形容超群出众，没有谁可与之相比。</li></ol></li><li><p><strong>69、鬼斧神工 巧夺天工</strong></p><ol><li><strong>[鬼斧神工]</strong>：形容艺术技巧高超，不是人力所能达到的。<code>适用对象：自然艺术.在句子中多作宾语，也可作主语、定语</code></li><li><strong>[巧夺天工]</strong>：形容技艺十分巧妙。<code>适用对象：人工，艺术，在句中做谓语、定语。</code></li></ol></li><li><p><strong>70、精美绝伦 美轮美奂</strong></p><ol><li><strong>[精美绝伦]</strong>：精致美妙，无与伦比。</li><li><strong>[美轮美奂]</strong>：形容房屋高大华丽。也形容装饰、布置等美好漂亮。</li></ol></li><li><p><strong>71、别具一格 别开生面</strong></p><ol><li><strong>[别具一格]</strong>：另有一种独特的风格。<code>风格不同，一般用于文艺创作</code></li><li><strong>[别开生面]</strong>：比喻另外创出一种新的形式或局面。<code>局面或形式不同，适用范围更广</code></li></ol></li><li><p><strong>72、一针见血 鞭辟入里 高屋建瓴 恰如其分</strong></p><ol><li><strong>[一针见血]</strong>：比喻说话直截了当，切中要害。<code>说话切中要害，作谓语、定语、状语</code></li><li><strong>[鞭辟入里]</strong>：形容作学问切实。也形容分析透彻，切中要害。<code>做学问或分析切实透彻，作谓语、补语</code></li><li><strong>[高屋建瓴]</strong>：把瓶子里的水从高层顶上倾倒。比喻居高临下，不可阻遏。<code>居高临下，把握全面透彻。作谓语</code></li><li><strong>[恰如其分]</strong>：指办事或说话正合分寸。<code>说话办事恰当，作谓语、宾语、状语</code></li></ol></li><li><p><strong>73、与众不同 出类拔萃 鹤立鸡群 卓尔不群</strong></p><ol><li><strong>[与众不同]</strong>：和众人不一样。</li><li><strong>[出类拔萃]</strong>：品行、才干大大高出同类而拔尖。<code>品行、才干，与同类比，可用在多个个体上</code></li><li><strong>[鹤立鸡群]</strong>：比喻卓越出众。<code>容貌、才干，和众人比，只用在一个个体上</code></li><li><strong>[卓尔不群]</strong>：高明杰出，不同凡响/超出常人。<code>不同寻常</code></li></ol></li><li><p><strong>74、不以为然 不以为意 不足为训 置若罔闻 置之不理</strong></p><ol><li><strong>[不以为然]</strong>：表示不同意或否定。</li><li><strong>[不以为意]</strong>：表示对人、事抱轻视态度。</li><li><strong>[不足为训]</strong>：足：够得上；训：法则，典范。不值得作为效法的准则或榜样。<code>不要效仿，不要学它</code></li><li><strong>[置若罔闻]</strong>：好像没有听见似的。指不予理睬。</li><li><strong>[置之不理]</strong>：放在一边，不理不睬。</li></ol></li><li><p><strong>75、不可或缺 必不可少 缺一不可 至关重要</strong></p><ol><li><strong>[不可或缺]</strong>：表示非常重要，不能有一点点的缺失，不能少一点。或：稍微。<code>非常重要的因素或部分</code></li><li><strong>[必不可少]</strong>：绝对需要，指不达到某种目的就不能做成某种事情。<code>必需的。注意，是“需”不是“须”。“必需”和“必须”的辨析见实词部分。</code></li><li><strong>[缺一不可]</strong>：少一样也不行。<code>一个都不能少</code></li><li><strong>[至关重要]</strong>：相当的重要，在要紧关头是不可缺少的，比喻最重要的。<code>强调最重要，最要紧</code></li></ol></li><li><p><strong>76、锦上添花 雪中送炭 画龙点睛</strong></p><ol><li><strong>[锦上添花]</strong>：在锦上再绣花。比喻好上加好，美上添美。<code>好上加好。作谓语、宾语、补语。含褒义</code></li><li><strong>[雪中送炭]</strong>：在下雪天给人送炭取暖。比喻在别人急需时给以物质上或精神上的帮助。<code>及时帮助。作谓语、宾语、定语</code></li><li><strong>[画龙点睛]</strong>：原形容梁代画家张僧繇作画的神妙。后多比喻写文章或讲话时，在关键处用几句话点明实质，使内容生动有力。<code>点明要旨，更加生动。</code></li></ol></li><li><p><strong>77、颇有微词 嗤之以鼻</strong></p><ol><li><strong>[颇有微词]</strong>：有很多<code>隐晦的</code>批评和不满的话语，表示对某人某事不满。<code>我对你不满</code></li><li><strong>[嗤之以鼻]</strong>：用鼻子轻蔑地吭气，表示瞧不起<code>我瞧不起你!</code></li></ol></li><li><p><strong>78、纸上谈兵 闭门造车 坐而论道</strong></p><ol><li><strong>[纸上谈兵]</strong>：比喻空谈理论，不能解决实际问题。也比喻空谈不能成为现实。<code>纯粹空谈，贬义</code></li><li><strong>[闭门造车<code>chē</code>]</strong>：比喻脱离实际，只凭主观办事。<code>办事主观不实际，贬义。适用语境：批评、劝告，作谓语、定语、状语</code></li><li><strong>[坐而论道]</strong>：坐着空谈大道理。指口头说说，不见行动。<code>光说白话不做事，简称口嗨王，贬义</code></li></ol></li><li><p><strong>79、求全责备 吹毛求疵</strong></p><ol><li><strong>[求全责备]</strong>：对人对事物要求十全十美，毫无缺点。<code>要求无缺点，完美主义</code></li><li><strong>[吹毛求疵]</strong>：比喻故意挑剔别人的缺点，寻找差错。<code>故意找茬，挑剔</code></li></ol></li><li><p><strong>80、妄自菲薄 妄自尊大 目空一切 唯我独尊 自惭形秽 自愧不如 自轻自贱</strong></p><ol><li><strong>[妄自菲薄]</strong>：形容看轻自己，形容自责、自卑心理。对自己的品德、能力等没有自信，不相信自己可以完成。<code>自卑</code></li><li><strong>[妄自尊大]</strong>：过高地看待自己。形容狂妄自大，不把别人放在眼里。<code>自大</code></li><li><strong>[目空一切]</strong>：什么都不放在眼里。形容极端骄傲自大。<code>骄傲自大，目中无人</code></li><li><strong>[唯我独尊]</strong>：现指认为只有自己最了不起。形容极端自高自大。<code>我最牛</code></li><li><strong>[自惭形秽]</strong>：形秽，形态丑陋，引申为缺点。因己不如别人而感到惭愧。<code>惭愧</code></li><li><strong>[自愧不如]</strong>：自己惭愧不如别人。<code>惭愧</code></li><li><strong>[自轻自贱]</strong>：自己看不起自己。多指自己降低身份。<code>自我贬低</code></li></ol></li><li><p><strong>81、好高骛远 急功近利 沽名钓誉</strong></p><ol><li><strong>[好高骛远]</strong>：比喻不切实际地追求过高过远的目标。</li><li><strong>[好大喜功]</strong>：指不管条件是否许可，一心想做大事立大功。多用以形容浮夸的作风。<code>浮夸爱出风头。贬义。</code></li><li><strong>[急功近利]</strong>：急于求成，贪图眼前的成效和利益。<code>太功利。</code></li><li><strong>[沽名钓誉]</strong>：用某种不正当的手段捞取名誉。<code>图名不正当。含贬义。</code></li></ol></li><li><p><strong>82、不可思议 难以置信 出乎意料 不可理喻 匪夷所思</strong></p><ol><li><strong>[不可思议]</strong>：多指无法想象，难以理解。</li><li><strong>[难以置信]</strong>：不容易相信。</li><li><strong>[出乎意料]</strong>：出乎人们意料之外。</li><li><strong>[不可理喻]</strong>：没法跟他讲道理。形容蛮横或固执。</li><li><strong>[匪夷所思]</strong>：考虑问题的方法、言语、行动违反常规，使人难以想象和理解。`离</li></ol></li><li><p><strong>83、想入非非 异想天开</strong></p><ol><li><strong>[想入非非]</strong>：形容完全脱离现实地胡思乱想。<code>不可能达到</code></li><li><strong>[异想天开]</strong>：指想法很不切实际，非常奇怪。<code>可能达到</code></li></ol></li><li><p><strong>84、举棋不定 犹豫不决 优柔寡断</strong></p><ol><li><strong>[举棋不定]</strong>：比喻犹豫不决，拿不定主意。<code>重大决策性问题</code></li><li><strong>[犹豫不决]</strong>：拿不定主意。<code>大小事</code></li><li><strong>[优柔寡断]</strong>：指做事犹豫，缺乏决断。<code>性格方面</code></li></ol></li><li><p><strong>85、叹为观止 令人赞叹 可圈可点 拍案叫绝 大开眼界</strong></p><ol><li><strong>[叹为观止]</strong>：指赞美所见到的事物好到了极点。</li><li><strong>[令人赞叹]</strong>：让人称赞，赞美。</li><li><strong>[可圈可点]</strong>：文章精彩，值得加以圈点，形容表现好，值得肯定或赞扬：影片中男女主角的表演都~。<code>表现好，值得肯定，搭配：表现、举措</code></li><li><strong>[拍案叫绝]</strong>：拍桌子叫好。形容非常赞赏。<code>褒义，适用对象：言论、行动、诗文，作谓语、宾语、补语</code></li><li><strong>[大开眼界]</strong>：开阔视野，增长见识。</li></ol></li><li><p><strong>86、乐此不疲 趋之若鹜</strong></p><ol><li><strong>[乐此不疲]</strong>：因酷爱干某事而不感觉厌烦。形容对某事特别爱好而沉浸其中。<code>沉浸其中。作谓语、定语</code></li><li><strong>[趋之若鹜]</strong>：像鸭子一样成群跑过去。比喻很多人争着赶去。<code>争赶跟风。含贬义。作谓语、定语</code></li></ol></li><li><p><strong>87、不言而喻 显而易见 有目共睹 呼之欲出 跃然纸上</strong></p><ol><li><strong>[不言而喻]</strong>：不用说话就能明白。形容道理很明显。<code>道理明显</code></li><li><strong>[显而易见]</strong>：形容事情或道理很明显，极容易看清楚。<code>说话、文章和事情等容易看清</code></li><li><strong>[有目共睹]</strong>：指非常明显，谁都看得见。<code>事物明显，不能隐讳</code></li><li><strong>[呼之欲出]</strong>：形容人像画得逼真，似乎叫一声就会从画中走出来。泛指文学作品中人物的描写十分生动。也指某事即将揭晓或出现。<code>逼真。适用对象：文艺、绘画</code></li><li><strong>[跃然纸上]</strong>：活跃地呈现在纸上。形容文学作品叙述描写真实生动。<code>适用对象：文学作品、艺术形象、风格、思想感情等</code></li></ol></li><li><p><strong>88、惟妙惟肖 栩栩如生 活灵活现 妙趣横生</strong></p><ol><li><strong>[惟妙惟肖]</strong>：形容描写或模仿得非常逼真、传神。<code>多指表演、模仿</code></li><li><strong>[栩栩如生]</strong>：指艺术形象非常逼真，如同活的一样。<code>多指艺术作品</code></li><li><strong>[活灵活现]</strong>：形容神情逼真，使人感到好像亲眼看到一般。<code>多形容神情</code></li><li><strong>[妙趣横生]</strong>：洋溢着美妙的意趣<code>多指语言、文章或美术作品</code>。<code>褒义。作谓语、定语、补语</code></li></ol></li><li><p><strong>89、如雷贯耳 振聋发聩 醍醐灌顶 掷地有声 茅塞顿开 恍然大悟 如梦初醒 涣然冰释</strong></p><ol><li><strong>[如雷贯耳]</strong>：响亮得象雷声传进耳朵里。形容人的名声大。<code>名声大</code></li><li><strong>[振聋发聩]</strong>：比喻用语言文字唤醒糊涂麻木的人，使他们清醒过来。<code>使人清醒</code></li><li><strong>[醍醐灌顶]</strong>：比喻听了高明的意见使人受到很大启发。也形容清凉舒适。<code>使人受启发</code></li><li><strong>[掷地有声]</strong>：比喻文章文辞优美，语言铿锵有力。现也形容落实力度大。<code>文辞优美、有力/落实力度大</code></li><li><strong>[茅塞顿开]</strong>：形容闭塞的思路，由于得到了某种事物的启发，忽然就想通了。<code>因启发，想通了</code></li><li><strong>[恍然大悟]</strong>：形容一下子明白过来。<code>突然明白</code></li><li><strong>[如梦初醒]</strong>：像从梦中醒来。比喻过去一直糊涂，在别人或事实的启发下，刚刚明白过来。<code>经启发，从糊涂中明白过来。意同“一语惊醒梦中人”</code>。</li><li><strong>[涣然冰释]</strong>：像冰遇热消融一般。形容疑虑、误会、隔阂等完全消除。<code>误会消除</code></li></ol></li><li><p><strong>90、石破天惊 惊天动地 一鸣惊人</strong></p><ol><li><strong>[石破天惊]</strong>：原形容箜篌的声音，忽而高亢，忽而低沉，出人意外，有难以形容的奇境。后多比喻文章议论新奇惊人。<code>文章议论新奇惊人</code></li><li><strong>[惊天动地]</strong>：形容某个事件的声势或意义极大。<code>声势或意义极大</code></li><li><strong>[一鸣惊人]</strong>：比喻平时不被人注意的人，突然做出了惊人的成绩。<code>成绩惊人</code></li></ol></li><li><p><strong>91、耸人听闻 骇人听闻</strong></p><ol><li><strong>[耸人听闻]</strong>：夸大或捏造事实，使人听了感到惊异或震动。<code>夸大或捏造</code></li><li><strong>[骇人听闻]</strong>：使人听了非常震惊、害怕。</li></ol></li><li><p><strong>92、信口开河 口若悬河 信口雌黄 口无遮拦</strong></p><ol><li><strong>[信口开河]</strong>：不加思索的随意乱说。 <code>强调乱说</code></li><li><strong>[口若悬河]</strong>：言谈有若滔滔流水，源源不绝于口，形容口才敏捷，善于辩解<code>强调口才好</code></li><li><strong>[信口雌黄]</strong>：古时写字用黄纸，写错了就用雌黄涂抹改写。比喻不顾事实，随意乱说。<code>强调不顾事实而乱批评</code></li><li><strong>[口无遮拦]</strong>：说话没有顾忌，有什么说什么。<code>强调说话的随意性</code></li></ol></li><li><p><strong>93、不经之谈 荒诞不经 空穴来风</strong></p><ol><li><strong>[不经之谈]</strong>：没有根据，不合情理的言论。<code>侧重没根据。使用对象：言论。</code></li><li><strong>[荒诞不经]</strong>：形容虚妄离奇，不合情理。<code>侧重离奇</code></li><li><strong>[空穴来风]</strong>：比喻消息和谣言的传播不是完全没有原因的。也比喻流言乘机会传开来。<code>无根据；流言传开</code></li></ol></li><li><p><strong>94、天马行空 空中楼阁 天方夜谭 海市蜃楼 天花乱坠 无稽之谈</strong></p><ol><li><strong>[天马行空]</strong>：比喻诗文书法等气势豪放，不拘一格，流畅自然，也指思维不同寻常的跳跃，还指不切实际的想法。<code>思维跳跃不实际</code></li><li><strong>[空中楼阁]</strong>：比喻虚幻的事物或脱离实际的空想。<code>不实际</code></li><li><strong>[天方夜谭]</strong>：比喻虚诞、离奇的议论。<code>荒诞</code></li><li><strong>[海市蜃楼]</strong>：比喻虚无缥缈的事情。 <code>缥缈</code></li><li><strong>[天花乱坠]</strong>：形容说话有声有色，极其动听<code>多指言语动听而不符合实际</code>。</li><li><strong>[危言耸听]</strong>：指故意夸大事实，说吓人的话使人吃惊。<code>吓唬人</code></li><li><strong>[无稽之谈]</strong>：没有根据的说法。<code>胡扯</code></li></ol></li><li><p><strong>95、拾人牙慧 子虚乌有 一纸空文 荒诞不经</strong></p><ol><li><strong>[拾人牙慧]</strong>：比喻拾取别人的一言半语当作自己的话。<code>拿来主义，贬义，作谓语、宾语</code></li><li><strong>[子虚乌有]</strong>：指假设的、不存在的、不真实的事情。<code>不存在，作定语、谓语、宾语</code></li><li><strong>[一纸空文]</strong>：只是写在纸上没有兑现或不能兑现的东西。<code>未兑现，未生效，只是个摆设，作主语、宾语</code></li><li><strong>[荒诞不经]</strong>：形容言论荒谬，不合情理。<code>言论荒谬，贬义，作谓语、宾语、定语</code></li></ol></li><li><p><strong>96、陈词滥调 老生常谈 老调重弹</strong></p><ol><li><strong>[陈词滥调]</strong>：指陈腐、空泛的论调。<code>贬义，陈旧又不合实际的话</code></li><li><strong>[老生常谈]</strong>：比喻人们听惯了的没有新鲜意思的话。<code>中性，单纯没有新意的话，不一定没有现实意义</code></li><li><strong>[老调重弹]</strong>：比喻把说过多次的理论、主张重新搬出来。也比喻把搁置很久的技艺重新做起来。<code>含贬义。一般作谓语、宾语。</code></li></ol></li><li><p><strong>97、不胜枚举 不可胜数 数不胜数 不一而足</strong></p><ol><li><strong>[不胜枚举]</strong>：形容数量很多。</li><li><strong>[不可胜数]</strong>：形容数量极多。</li><li><strong>[数不胜数]</strong>：形容数量极多，很难计算。</li><li><strong>[不一而足]</strong>：指同类的事物不只一个而是很多，无法列举齐全。<code>同类事物很多。一般置于句子末尾。一般作谓语、分句。</code></li></ol></li><li><p><strong>98、层出不穷 比比皆是 司空见惯 纷至沓来 屡见不鲜 无处不在 习以为常</strong></p><ol><li><strong>[层出不穷]</strong>：比喻事物或言论接连不断地出现，尚未穷尽，数量多。<code>数量多。作谓语、定语</code></li><li><strong>[比比皆是]</strong>：到处都是。形容极其常见，对象可是人，也可是物。<code>极其常见，作谓语</code></li><li><strong>[司空见惯]</strong>：某事常见，不足为奇，偏向描述事物，多用于书面语。<code>经常见到，不奇怪，一般作谓语、定语、宾语</code></li><li><strong>[纷至沓来]</strong>：形容连续不断地到来。<code>到来，多用于书面语，作谓语、定语</code>例句：李大夫能治好障碍性贫血病的消息不胫而走，求医的癌症患者纷至沓来&lt;作谓语&gt;。</li><li><strong>[屡见不鲜]</strong>：多次见到，已经不新奇了，通常指不好现象。<code>强调普遍性，作定语、补语、状语</code></li><li><strong>[无处不在]</strong>：到处都存在，到处都有。<code>存在的范围广，数量多。作谓语、定语</code></li><li><strong>[习以为常]</strong>：某种事情经常做，或经常看到，很平常。</li></ol></li><li><p><strong>99、星罗棋布 包罗万象</strong></p><ol><li><strong>[星罗棋布]</strong>：形容数量多，分布广。<code>强调数量和分布</code></li><li><strong>[包罗万象]</strong>：形容内容丰富、情况复杂，无所不有。<code>强调内容丰富</code></li></ol></li><li><p><strong>100、浩如烟海 汗牛充栋</strong></p><ol><li><strong>[浩如烟海]</strong>：形容文献、资料、书籍繁多或丰富。</li><li><strong>[汗牛充栋]</strong>：形容藏书很多。</li></ol></li><li><p><strong>101、美不胜收 琳琅满目</strong></p><ol><li><strong>[美不胜收]</strong>：美好的东西很多，一时看不过来。<code>侧重看不过来</code></li><li><strong>[琳琅满目]</strong>：满眼都是珍贵的东西。形容美好的事物很多。<code>侧重事物多</code></li></ol></li><li><p><strong>102、鳞次栉比 错落有致</strong></p><ol><li><strong>[鳞次栉比]</strong>：象鱼鳞和梳子齿那样有次序地排列着。多用来形容房屋或船只等排列得很密很整齐。<code>房屋或船只集中而排列整齐，作谓语、定语</code></li><li><strong>[错落有致]</strong>：交错纷杂而有情趣。<code>适用语境：用于形容事物安排布置得巧妙；令人喜爱。</code></li></ol></li><li><p><strong>103、珠联璧合 相辅相成 相得益彰</strong></p><ol><li><strong>[珠联璧合]</strong>：珍珠联串在一起，美玉结合在一块。比喻杰出的人才或美好的事物结合在一起。<code>好的结合，褒义，作谓语、宾语</code></li><li><strong>[相辅相成]</strong>：指两件事物互相配合，互相辅助，缺一不可。<code>相互依存，作谓语、定语</code></li><li><strong>[相得益彰]</strong>：指两个人或两件事物互相配合，双方的能力和作用更能显示出来。<code>相互配合，褒义，作谓语</code></li></ol></li><li><p><strong>104、息息相关 休戚相关 休戚与共</strong></p><ol><li><strong>[息息相关]</strong>：彼此呼吸都连在一起，形容关系十分密切。<code>我们共住地球村，生在红旗下，长在春风里</code></li><li><strong>[休戚相关]</strong>：彼此间的忧喜祸福相关联，形容关系十分密切。<code>你若安好，便是晴天</code></li><li><strong>[休戚与共]</strong>：忧喜、祸福彼此共同承担。形容关系密切，利害相同，同欢乐共悲哀。同“患难与共”。<code>共同承担危险和困难。形容彼此之间关系密切，利害一致</code></li></ol></li><li><p><strong>105、不可多得 寥寥无几 屈指可数 凤毛麟角</strong></p><ol><li><strong>[不可多得]</strong>：形容非常稀少，很难得到<code>多指人才或稀有物品，强调数量少，难得到</code></li><li><strong>[寥寥无几]</strong>：形容数量少。非常稀少，没有几个。<code>形容的数目比较抽象，不能用来计算时间</code></li><li><strong>[屈指可数]</strong>：形容数目少，扳着手指头就能数过来。<code>形容的数目具体形象，能够用来记录日期</code></li><li><strong>[凤毛麟角]</strong>：比喻珍贵而稀少的人或物。<code>不仅稀有，而且珍贵，强调事物价值。近义词：吉光片羽</code></li></ol></li><li><p><strong>106、接踵而来 络绎不绝 纷至沓来</strong></p><ol><li><strong>[接踵而来]</strong>：指人们前脚跟着后脚，接连不断地来，形容来者很多，络绎不绝<code>人多</code></li><li><strong>[络绎不绝]</strong>：形容人、马、车船等连续不断。<code>人多、车马多，与接踵而来基本同义</code></li><li><strong>[纷至踏来]</strong>：形容接连不断地到来。<code>不同地方、不同的人</code></li></ol></li><li><p><strong>107、此起彼伏 层出不穷</strong></p><ol><li><strong>[此起彼伏]</strong>：这里起来，那里下去。形容接连不断。<code>侧重于兴起</code></li><li><strong>[层出不穷]</strong>：接连不断地出现，没有穷尽。<code>侧重于没有穷尽。作谓语、定语</code></li></ol></li><li><p><strong>108、目不暇接 应接不暇</strong></p><ol><li><strong>[目不暇接]</strong>：指东西多，眼睛都看不过来。<code>单纯指东西多，看不过来</code></li><li><strong>[应接不暇]</strong>：满眼都是珍贵的东西。形容美好的事物很多。<code>可形容事情忙，难以应酬</code></li></ol></li><li><p><strong>109、集腋成裘 积沙成塔 积少成多</strong></p><ol><li><strong>[集腋成裘]</strong>：比喻积少成多。<code>书面语，多用在好的方面</code></li><li><strong>[积沙成塔]</strong>：比喻积少成多。</li><li><strong>[积少成多]</strong>：积累少量的东西，能成为巨大的数量。</li></ol></li><li><p><strong>110、历久弥新 经久不衰</strong></p><ol><li><strong>[历久弥新]</strong>：指经历长久的时间而更加鲜活，更加有活力，更显价值。或者指一样东西不因时间而变旧，变腐，比新的还好。</li><li><strong>[经久不衰]</strong>：形容某事或某人经历很长时间仍旧保持较高的旺盛状态。</li></ol></li><li><p><strong>111、信手拈来 手到擒来 唾手可得 俯拾皆是 触手可及</strong></p><ol><li><strong>[信手拈来]</strong>：随手拿来。多指写文章时能自由纯熟的选用词语或应用典故，用不着怎么思考。<code>适用语境：多用于写作或言谈，作谓语、定语、状语</code></li><li><strong>[手到擒来]</strong>：原指作战一下子就能把敌人捉拿过来，后比喻做事有把握，不费力就做好了。<code>做事有把握，不费力，褒义</code></li><li><strong>[唾手可得]</strong>：动手就可以取得。比喻极容易得到。<code>易得到，作谓语</code></li><li><strong>[俯拾皆是]</strong>：只要低下头来捡取，到处都是。形容多而易得。<code>多而易得，书面语</code></li><li><strong>[触手可及]</strong>：近在手边，一伸手就可以接触到。<code>距离近，很容易。作宾语、定语</code></li></ol></li><li><p><strong>112、相提并论 等量齐观 混为一谈 同日而语 一视同仁</strong></p><ol><li><strong>[相提并论]</strong>：把相差悬殊的人或事放在一起看待，侧重有差距。</li><li><strong>[等量齐观]</strong>：把有差别的事物同等看待，侧重有差别。</li><li><strong>[混为一谈]</strong>：把不同的事物放在一起讨论，侧重本质不同。</li><li><strong>[同日而语]</strong>：指放在同一时间讨论，侧重时间上的对比。</li><li><strong>[一视同仁]</strong>：多表示对人同样看待，不分厚薄。<code>不同的人，同一标准看待</code></li></ol></li><li><p><strong>113、欣欣向荣 方兴未艾 如日中天 如火如荼 风靡一时 异军突起 江河日下</strong></p><ol><li><strong>[欣欣向荣]</strong>：形容草木长得茂盛。比喻事业蓬勃发展，兴旺昌盛。<code>草木或事业的蓬勃发展，褒义，作谓语、定语、状语</code></li><li><strong>[方兴未艾]</strong>：事物正在发展，尚未达到止境。<code>正在发展的革命形势和新生事物，作宾语、定语</code></li><li><strong>[如日中天]</strong>：好像太阳正在天顶。比喻事物正发展到十分兴盛的阶段。<code>发展到了兴盛阶段，褒义，作谓语、定语</code></li><li><strong>[如火如荼]</strong>：象火那样红，象荼那样白。原比喻军容之盛。现用来形容大规模的行动气势旺盛，气氛热烈。<code>气势旺盛，气氛热烈，褒义，作谓语、定语、状语</code></li><li><strong>[风靡一时]</strong>：形容事物在一个时期里极其盛行，象风吹倒草木一样。<code>盛行，流行，适用对象：小说、戏剧、歌曲、服装，或某种现象问题，作谓语、定语</code></li><li><strong>[异军突起]</strong>：比喻一支新生力量突然出现。<code>含褒义。作谓语、宾语、补语</code></li><li><strong>[江河日下]</strong>：江河的水一天天向下流。比喻情况一天天地坏下去。<code>越来越坏，糟了</code></li></ol></li><li><p><strong>114、瞬息万变 一日千里 日新月异 变幻莫测 波谲云诡</strong></p><ol><li><strong>[瞬息万变]</strong>：形容变化很多很快</li><li><strong>[一日千里]</strong>：比喻进展极快。</li><li><strong>[日新月异]</strong>：指发展或进步迅速，不断出现新事物、新气象。</li><li><strong>[变幻莫测]</strong>：变化很多，不能意料。</li><li><strong>[波谲云诡]</strong>：事物变幻莫测。</li></ol></li><li><p><strong>115、日新月异 一日千里 今非昔比</strong></p><ol><li><strong>[日新月异]</strong>：每天都在更新，每月都有变化。指发展或进步迅速，不断出现新事物、新气象。<code>褒义，发展进步迅速</code></li><li><strong>[一日千里]</strong>：原形容马跑得很快。后比喻进展极快。<code>褒义，进展快</code></li><li><strong>[今非昔比]</strong>：现在不是过去能比得上的。多指形势、自然面貌等发生了巨大的变化。<code>中性词。适用语境：环境、生活发生大变化。</code></li></ol></li><li><p><strong>116、势如破竹 势不可挡 势在必行 大势所趋</strong></p><ol><li><strong>[势如破竹]</strong>：形势就象劈竹子，头上几节破开以后，下面各节顺着刀势就分开了。比喻节节胜利，毫无阻碍。<code>节节胜利无阻碍。褒义。作谓语、定语、状语</code></li><li><strong>[势不可挡]</strong>：来势迅猛，不可抵挡。<code>难抵挡</code></li><li><strong>[势在必行]</strong>：事情已经非做不可了。<code>必须这么做</code></li><li><strong>[大势所趋]</strong>：整个局势发展的趋向。<code>趋势是这样</code></li></ol></li><li><p><strong>117、革故鼎新 推陈出新</strong></p><ol><li><strong>[革故鼎新]</strong>：旧指朝政变革或改朝换代。现泛指除去旧的，建立新的。<code>多用于制度创新层面</code></li><li><strong>[推陈出新]</strong>：指对旧的文化进行批判地继承，剔除其糟粕，吸取其精华，创造出新的文化。<code>多用于文化遗产的继承方面</code></li></ol></li><li><p><strong>118、首当其冲 当务之急 迫在眉睫 势在必行</strong></p><ol><li><strong>[首当其冲]</strong>：比喻最先受到攻击或遭到灾难。<code>首先遭殃。作谓语、定语</code></li><li><strong>[当务之急]</strong>：<code>名词</code>当前任务中最急切要办的事。<code>常作判断句中的主语或“是”、“成为”等的宾语。作主语、宾语</code></li><li><strong>[迫在眉睫]</strong>：形容事情已到眼前，情势十分紧迫。<code>火烧眉毛不能等，作谓语、定语</code></li><li><strong>[势在必行]</strong>：从事情的发展趋势看，必须采取行动。<code>非做不可</code></li></ol></li><li><p><strong>119、应运而生 蔚然成风</strong></p><ol><li><strong>[应运而生]</strong>：旧指应天命而产生。现指适应时机而产生。<code>顺应时代需要。作谓语、定语</code></li><li><strong>[蔚然成风]</strong>：指一件事情逐渐发展盛行，形成一种良好风气。<code>良好风气形成</code></li></ol></li><li><p><strong>120、朝不保夕 危在旦夕 岌岌可危 奄奄一息 不绝如缕</strong></p><ol><li><strong>[朝不保夕]</strong>：早上无法保证晚上命运如何。形容形势严峻，很难维计<code>很可能活不下去，死亡概率 $56 \\%$</code></li><li><strong>[危在旦夕]</strong>：危险就在眼前<code>生死关头，是否能活下去难说，死亡概率50%</code></li><li><strong>[岌岌可危]</strong>：形容非常危险<code>有危险，但死亡概率不知</code></li><li><strong>[奄奄一息]</strong>：仅存微弱的一口气，形容生命或事物已经到了最后时刻<code>命不久矣， 死亡概率 99%</code></li></ol></li><li><p><strong>121、持之以恒 锲而不舍</strong></p><ol><li><strong>[持之以恒]</strong>：长久坚持下去。 <code>侧重长久长远</code></li><li><strong>[锲而不舍]</strong>：比喻有恒心，有毅力。<code>侧重坚定意志不放弃。作谓语、定语、状语</code></li></ol></li><li><p><strong>122、一如既往 一以贯之 始终如一</strong></p><ol><li><strong>[一如既往]</strong>：指态度没有变化，完全象从前一样。<code>从未改变。褒义。作谓语、定语、状语</code></li><li><strong>[一以贯之]</strong>：用一个根本性的事理贯通事情的始末或全部的道理。<code>贯彻执行，一直如此。</code></li><li><strong>[始终如一]</strong>：自始自终一个样子。指能坚持，不间断。<code>坚持不间断。适用语境：形容优良的品德、好的行为坚持不变。作谓语、定语</code></li></ol></li><li><p><strong>123、费尽心机 绞尽脑汁 处心积虑 殚精竭虑 挖空心思 千方百计</strong></p><ol><li><strong>[费尽心机]</strong>：用尽心思，千方百计的谋算。<code>不仅烧脑，而且打算盘</code></li><li><strong>[绞尽脑汁]</strong>：形容费尽心思，用尽脑力，尽力思考。<code>烧脑，CPU 占用率飙升</code></li><li><strong>[处心积虑]</strong>：心里计划思考已久，蓄谋已久。<code>算盘打得久，准备干坏事</code></li><li><strong>[殚精竭虑]</strong>：形容耗尽精力，费尽心思。<code>已经付出了心力</code></li><li><strong>[挖空心思]</strong>：比喻费尽心思，想尽一切办法。<code>特别烧脑</code></li><li><strong>[千方百计]</strong>：想尽或用尽一切办法。<code>同时包含想和做的成分</code></li></ol></li><li><p><strong>124、浮光掠影 走马观花 蜻蜓点水 浅尝辄止</strong></p><ol><li><strong>[浮光掠影]</strong>：比喻观察不细致，学习不深入，印象不深刻。<code>观察不细，印象不深</code></li><li><strong>[走马观花]</strong>： 多指大略地观察一下。<code>观察粗略，走过场</code></li><li><strong>[蜻蜓点水]</strong>：比喻做事肤浅不深入。 <code>做事肤浅</code></li><li><strong>[浅尝辄止]</strong>：略微尝试一下就停下来。指不深入钻研。<code>不深入</code></li></ol></li><li><p><strong>125、水涨船高 如影随形 随波逐流 相形见绌 黯然失色</strong></p><ol><li><strong>[水涨船高]</strong>：比喻事物随着它所凭借的基础的提高而提高。<code>强调变化</code></li><li><strong>[如影随形]</strong>：比喻两个事物关系密切或两个人关系密切不能分离。<code>强调两者关系密切</code></li><li><strong>[随波逐流]</strong>：比喻没有原则或主见，只是随大流，跟着别人走。<code>强调原则问题</code></li><li><strong>[相形见绌]</strong>：跟另一人或事物比较之后，显出了不足。<code>侧重通过对比显现出自身的不足</code></li><li><strong>[黯然失色]</strong>：比喻相比之下有很大差距，远远不如。<code>侧重自身失去原有的光彩或优势，显得暗淡无光</code></li></ol></li><li><p><strong>126、交相辉映 相映成趣 大放异彩</strong></p><ol><li><strong>[交相辉映]</strong>：各种光亮、色彩等相互映照。如：国庆之夜，满城的彩灯与腾空的焰火交相辉映。<code>多形容美好的景象。作谓语、定语</code></li><li><strong>[相映成趣]</strong>：相互映照、衬托，显得更有情趣。<code>以两种以上的事物为陈述对象。一般作谓语</code></li><li><strong>[大放异彩]</strong>：闪耀着无比灿烂的光辉，散发出奇异的光彩或色彩。比喻有着优异的表现或是突出的成就。<code>表现优异，成绩突出</code></li></ol></li><li><p><strong>127、沁人心脾 心旷神怡 赏心悦目</strong></p><ol><li><strong>[沁人心脾]</strong>：原指芳香凉爽的空气或饮料使人感到舒适。也形容诗歌和文章优美动人，给人清新爽朗的感觉。<code>清新爽朗。作谓语、定语。含褒义</code></li><li><strong>[心旷神怡]</strong>：心境开阔，精神愉快。<code>心境好。适用语境：多用于欣赏自然景色或诗文绘画的场合。作谓语、状语</code></li><li><strong>[赏心悦目]</strong>：指看到美好的景色而心情愉快。<code>心情好。使用语境：形容文章或景色优雅。作谓语、定语</code></li></ol></li><li><p><strong>128、筚路蓝缕 栉风沐雨 披荆斩棘</strong></p><ol><li><strong>[筚路蓝缕]</strong>：驾着简陋的车，穿着破烂的衣服去开辟山林。形容创业的艰苦。<code>创业艰苦，书面语，作谓语、定语、状语</code></li><li><strong>[栉风沐雨]</strong>：风梳发，雨洗头。形容在外奔波，不避风雨，历尽艰辛。</li><li><strong>[披荆斩棘]</strong>：比喻在创业过程中或前进道路上清除障碍，克服重重困难。<code>克服困难</code></li></ol></li><li><p><strong>129、同舟共济 众志成城 同甘共苦 相濡以沫</strong></p><ol><li><strong>[同舟共济]</strong>：坐一条船，共同渡河。比喻团结互助，同心协力，战胜困难。也比喻利害相同。<code>侧重共同战胜苦难。作谓语、定语</code></li><li><strong>[众志成城]</strong>：万众一心，象坚固的城墙一样不可摧毁。比喻团结一致，力量无比强大。<code>侧重团结一致。作谓语、定语</code></li><li><strong>[同甘共苦]</strong>：共同享受幸福，共同担当艰苦。<code>有福同享有难同当。作谓语、定语、状语</code></li><li><strong>[相濡以沫]</strong>：泉水干了，鱼吐沫互相润湿。比喻一同在困难的处境里，用微薄的力量互相帮助。<code>相互帮助。书面语</code></li></ol></li><li><p><strong>130、讳疾忌医 因噎废食</strong></p><ol><li><strong>[讳疾忌医]</strong>：比喻掩饰自己的缺点错误，不愿接受批评帮助。</li><li><strong>[因噎废食]</strong>：比喻因为出了一点问题或者怕出问题，就把本来应该做的事情放下不做。</li></ol></li><li><p><strong>131、妙手偶得 灵机一动</strong></p><ol><li><strong>[妙手偶得]</strong>：指指创作或者研究的灵感，可以偶然间得到 。</li><li><strong>[灵机一动]</strong>：指急忙中转了一下念头，多指临时想了个办法解决眼前棘手的问题。</li></ol></li></ol><h2 id="二、实词辨析" tabindex="-1">二、实词辨析 <a class="header-anchor" href="#二、实词辨析" aria-label="Permalink to “二、实词辨析”">​</a></h2><ol><li><strong>1、严密 周密 缜密 细密</strong><ol><li><strong>[严密]</strong>：指考虑周详，没有疏漏，侧重于紧密，无懈可击，多指防守、防备、监视、观察等。</li><li><strong>[周密]</strong>：侧重于周全、细致、完备，多指考虑、计划、安排、调查等。</li><li><strong>[缜密]</strong>：指周密、细致，多指人的思想。</li><li><strong>[细密]</strong>：指仔细的意思。</li></ol></li><li><strong>2、必须 必需</strong><ol><li><strong>[必须]</strong>：情理上的必要。</li><li><strong>[必需]</strong>：非有不可的，不能少的。</li></ol></li><li><strong>3、必然 必定</strong><ol><li><strong>[必然]</strong>：坚定不移的趋势，必定这样。</li><li><strong>[必定]</strong>：表示判断或推论的确凿/表示意志的坚决。</li></ol></li><li><strong>4、装载 承载 承受</strong><ol><li><strong>[装载]</strong>：用运输工具装人或物资。</li><li><strong>[承载]</strong>：承受负载/承受支撑物体。</li><li><strong>[承受]</strong>：接受，承担。</li></ol></li><li><strong>5、沉淀 积淀 积累 荟萃 融合</strong><ol><li><strong>[沉淀]</strong>：从溶液中析出固体物质的过程，或指在该过程中析出的固体物质。广泛用于物质的分离</li><li><strong>[积淀]</strong>：积累沉淀。所积累沉淀下来的事物。<code>多指文化、知识、经验等</code></li><li><strong>[积累]</strong>： <code>事物</code>逐渐积聚。</li><li><strong>[荟萃]</strong>：<code>英俊的人物或精美的东西</code>会集；聚集。如荟萃一堂。</li><li><strong>[融合]</strong>：几种不同的事物合成一体。</li></ol></li><li><strong>6、质疑 怀疑 狐疑 疑心</strong><ol><li><strong>[质疑]</strong>：提出疑问以求解答。<code>常见搭配：回应……质疑；饱受质疑；质疑…… 的合理性/可行性；遭到……质疑</code></li><li><strong>[怀疑]</strong>：疑惑，不很相信；猜测。</li><li><strong>[狐疑]</strong>：推测，凭想象估计。</li><li><strong>[疑心]</strong>：怀疑的念头。</li></ol></li><li><strong>7、表现 体现 展现 展示 呈现</strong><ol><li><strong>[表现]</strong>：显露出来。</li><li><strong>[体现]</strong>：具体形象地表现出来。</li><li><strong>[展现]</strong>：展示显现。</li><li><strong>[展示]</strong>：摆出来让人看。</li><li><strong>[显现]</strong>：显露，呈现。</li><li><strong>[呈现]</strong>：显出，指非刻意安排下所看到的样子。</li></ol></li><li><strong>8、构建 搭建</strong><ol><li><strong>[构建]</strong>：建立<code>多用于抽象事物</code>，比如构建学科体系。</li><li><strong>[搭建]</strong>：搭盖；建立<code>组织机构</code>，如搭建平台，搭建桥梁。</li></ol></li><li><strong>9、品味 品位</strong><ol><li><strong>[品位]</strong>：品级；档次，如努力提高娱乐性节目的文化品位。</li><li><strong>[品味]</strong>：品尝，引申为玩味，如你品，你细品！</li></ol></li><li><strong>10、象征 寓意 含义 内涵</strong><ol><li><strong>[象征]</strong>：以具体的事物体现某种特殊意义，如红色象征革命；用以体现某种的特殊意义的事物，如鸽子和平的象征。<code>一种符号形象</code></li><li><strong>[寓意]</strong>：假言他物而寄托本意。<code>借物抒情</code></li><li><strong>[含义]</strong>：词句所包含的意义；暗示。示意，涵义。<code>事物本身具有的意义</code></li><li><strong>[内涵]</strong>： 一个概念所反映的事物的本质属性的总和，也就是概念的内容。</li><li><strong>[意义]</strong>：语言文字或其他信号所表示的内容；价值；作用。</li></ol></li><li><strong>11、流逝 流失 消逝</strong><ol><li><strong>[流逝]</strong>：像流水一样快速消逝，比如时光流逝，岁月流逝。</li><li><strong>[流失]</strong>：泛指有用的东西流散失去，如抢救流失的文物；水土流失；比喻人员离开本地或本单位，如人才流失。</li><li><strong>[消逝]</strong>：<code>声音、时间等</code>慢慢逝去，不再存在。如永不消逝的电波</li></ol></li><li><strong>12、演绎 彰显</strong><ol><li><strong>[演绎]</strong>：铺陈，推断，阐发；演绎推理的简称。</li><li><strong>[彰显]</strong>：明显，显著；鲜明地显示。<code>多搭配品格、精神、使命</code></li></ol></li><li><strong>13、凸显 突显 显现 表明</strong><ol><li><strong>[突显]</strong>：突出地显示出，如青筋突显。</li><li><strong>[凸显]</strong>：清楚地显出，如草地上凸显出一座花坛，再如市场规范化的问题日益凸显出来。</li><li><strong>[显现]</strong>：显露，呈现。</li><li><strong>[表明]</strong>：表示清楚。</li></ol></li><li><strong>14、制定 制订</strong><ol><li><strong>[制定]</strong>：定出；拟定，如制定计划。<code>完成时</code></li><li><strong>[制订]</strong>：拟订，如制订方案。<code>进行时</code></li></ol></li><li><strong>15、缺少 缺乏 匮乏</strong><ol><li><strong>[缺少]</strong>：短缺，缺乏。<code>词义最轻</code></li><li><strong>[缺乏]</strong>：不足，缺少。<code>词义次轻</code></li><li><strong>[匮乏]</strong>：缺乏，贫乏，如物资匮乏。<code>词义最重</code></li></ol></li><li><strong>16、本质 实质</strong><ol><li><strong>[本质]</strong>：指事物本身固有的、决定事物性质、面貌和发展的根本属性。如中国特色社会主义最本质的特征就是中国共产党的领导。</li><li><strong>[实质]</strong>：内在实际的属性，跟表面的虚假的东西相对。如问题的实质、精神实质。</li></ol></li><li><strong>17、放弃 抛弃 摒弃</strong><ol><li><strong>[放弃]</strong>：丢掉<code>原有的权利、主张、意见等</code>抽象、具体事物都可。如放弃索赔 的权利，放弃机会。<code>词义最轻</code></li><li><strong>[抛弃]</strong>：扔掉不要。抽象事物、具体事物都可。如抛家弃子。<code>词义次轻</code></li><li><strong>[摒弃]</strong>：多指抽象事物，如思想、观点、文化遗产中的糟粕。<code>词义最重</code></li></ol></li><li><strong>18、保存 保留</strong><ol><li><strong>[保存]</strong>：保护事物、性质、力量等继续存在不受损失。多用在具体事物上，如保存资料、保存革命史迹</li><li><strong>[保留]</strong>：留下；暂时留着不处理。多用在保留抽象事物上，如保留面貌、保留意见、保留解释权等</li></ol></li><li><strong>19、补充 补偿 弥补 充实 丰富</strong><ol><li><strong>[补充]</strong>：不足的，增加一部分。如补充证据。</li><li><strong>[补偿]</strong>：抵消<code>损失、消耗</code>；补足<code>差额、欠缺</code>如补偿损失。</li><li><strong>[弥补]</strong>：把不够的部分填足。如弥补过错、弥补漏洞。</li><li><strong>[充实]</strong>：丰富；充足；内容或人力物力配备。如充实军队，充实文章内容。</li><li><strong>[丰富]</strong>：种类多，数量大；极为多彩的；充裕的，很多的；涉及面广的；使丰富。</li></ol></li><li><strong>20、引导 引领 重塑 改变 影响</strong><ol><li><strong>[引导]</strong>：带领，使跟随；启发；领导。<code>带领</code></li><li><strong>[引领]</strong>：指带动事物跟随他或他们向某一方向运动、发展。一般多用于人类社会。 <code>常用搭配：引领未来、党建引领、政治引领</code></li><li><strong>[重塑]</strong>：重新塑造。<code>塑造</code></li><li><strong>[改变]</strong>：事物变得和原来不一样；改换，更改。<code>更改</code></li><li><strong>[影响]</strong>：以间接或无形的方式来作用或改变人或事的行为、实现那个或性质。<code>作用</code></li></ol></li><li><strong>21、开辟 开拓 开发 开创 发展</strong><ol><li><strong>[开辟]</strong>：打通；开拓<code>如开辟光辉的未来</code>；创立<code>如开辟航线</code>；开办<code>如开辟专栏``侧重打通、开办</code></li><li><strong>[开拓]</strong>：扩大，扩充；开辟。<code>搭配：开拓市场、开拓土地</code></li><li><strong>[开发]</strong>：通过研究或努力，开拓、发现、利用新的资源或新的领域。如开发能源、开发软件<code>侧重研究利用</code></li><li><strong>[开创]</strong>：创立，开拓创建。如开创未来、开创新局面<code>侧重创立</code></li><li><strong>[发展]</strong>：事物由小到大、由简单到复杂、由低级到高级的变化；发育，进展；组织规模等扩大。如发展人工智能、发展高科技<code>侧重做大做强</code></li></ol></li><li><strong>22、推动 推进 引发 引导</strong><ol><li><strong>[推动]</strong>：使工作展开。<code>事情未开始，还在准备阶段</code></li><li><strong>[推进]</strong>：推动前进。<code>事物开始后的进一步发展</code></li><li><strong>[引发]</strong>：引起，触发。<code>强调结果，如引发了山火</code></li><li><strong>[引导]</strong>：带领，跟随；启发，领导。</li></ol></li><li><strong>23、推翻 颠覆 重构 改变</strong><ol><li><strong>[推翻]</strong>：把树立之物推倒；打垮原来的政权或社会制度；否定已有的说法、计划、 决定等。</li><li><strong>[颠覆]</strong>：改变事物原有的模样。颠倒顺序；摧毁；灭亡。</li><li><strong>[重构]</strong>：在某些原有的基础上，可以说原有的东西重新梳理修改加入某些东西， 使其达到更好的效果 。</li><li><strong>[改变]</strong>：事物发生显著的差别。</li></ol></li><li><strong>24、打破 突破 破解 破除 解除</strong><ol><li><strong>[打破]</strong>：突破原有的限制和约束；使突然结束；没有遵循或遵守。<code>搭配：打破僵局、打破传统、打破记录</code></li><li><strong>[突破]</strong>：打开缺口；超过；打破。</li><li><strong>[破解]</strong>：分析解释；排解使消除误会；解除。<code>搭配：破解难题、破解密码</code></li><li><strong>[破除]</strong>：除去；消除；败坏等。<code>搭配：破除封建迷信</code></li><li><strong>[解除]</strong>：免除。<code>搭配：解除职务、解除警报</code></li></ol></li><li><strong>25、打造 塑造 改造 营造</strong><ol><li><strong>[打造]</strong>：制造、创造的意思。<code>适用对象可为具体事物，如打造金银首饰，也可 为抽象概念，如打造品牌、打造精品力作、打造示范区。侧重于创造事物的决 心。</code></li><li><strong>[塑造]</strong>：用语言文字等艺术手段描写人物形象。<code>适用对象：人物形象，侧重于事物描 写的过程</code></li><li><strong>[改造]</strong>：修改或变更原事物，使适合需要；从根本上改变旧的，建立新的。<code>侧重于 弃旧从新的需要</code></li><li><strong>[营造]</strong>：建造，构造，编造。<code>侧重于营求达到的目的效果</code></li></ol></li><li><strong>26、衍生 孕育 滋养 涵养</strong><ol><li><strong>[衍生]</strong>：演变而产生；实际上或理论上从母体物质得到的。</li><li><strong>[孕育]</strong>：比喻在既存的事物中酝酿着新事物。</li><li><strong>[滋养]</strong>：养育，培养；提供养分养料。</li><li><strong>[涵养]</strong>：<code>名词</code>修养；<code>动词</code>滋润养育。</li></ol></li><li><strong>27、传承 继承 延续 沿袭 延伸 蔓延 传递 传播</strong><ol><li><strong>[传承]</strong>：泛指学问、技艺等的传授和继承。</li><li><strong>[继承]</strong>：继续做前人未完成的事业。<code>适用对象：传统、作风、精神、遗志等</code></li><li><strong>[延续]</strong>：照原来的样子继续下去。<code>适用对象：血脉、文脉、政策、做法、态势等</code></li><li><strong>[沿袭]</strong>：依照旧传统或规定办理；因袭。<code>旧传统、旧办法或规定，强调承前</code></li><li><strong>[延伸]</strong>：延长；扩大宽度、大小、范围。<code>侧重线性延长</code></li><li><strong>[蔓延]</strong>：向四周扩展延伸。<code>侧重向四周扩散，搭配：火势蔓延、疫情蔓延、危机蔓延</code></li><li><strong>[传递]</strong>：递过去，辗转递送；一个接一个送过去。<code>依次往下一个传送，搭配：传递爱心、传递火炬、传递力量、传递信号</code></li><li><strong>[传播]</strong>：传送或散布<code>如传播知识</code>；传染<code>如虱子传播疾病</code>；广泛散布<code>负责传播书籍的图书馆员及出版者</code>；使普遍知道<code>传播情报</code>。</li></ol></li><li><strong>28、解析 解读 评析 剖析 分析</strong><ol><li><strong>[解析]</strong>：解释分析。</li><li><strong>[解读]</strong>：阅读解释，如解读信息编码；分析，研究，如解读史前文化；理解，体会，如持不同观点的人对这项政策会有不同的解读。</li><li><strong>[评析]</strong>：评论分析。</li><li><strong>[剖析]</strong>：分析，辨析，如剖析事理，剖析人物性格。</li><li><strong>[]</strong>：将事物、现象、概念分门别类，离析出本质及其内在联系。</li></ol></li><li><strong>29、判断 评价 权衡 调节</strong><ol><li><strong>[判断]</strong>：估计<code>如品质、行为或人的</code>程度、力量、价值或性格；分析裁定。<code>侧重于分析预估的过程</code></li><li><strong>[评价]</strong>：评估价值；对人或事物所评定的价值。<code>侧重于价值评估的结果</code></li><li><strong>[权衡]</strong>：法度，标准；平量，比较。<code>侧重于比较取舍</code></li><li><strong>[调节]</strong>：在数量、程度、规模等方面进行调整，使符合标准。<code>侧重于调整的目的</code></li><li><strong>[调整]</strong>：重新调配整顿，使适应新的情况和要求。</li></ol></li><li><strong>30、洞察 掌握 了解</strong><ol><li><strong>[洞察]</strong>：发现内在的内容或意义。例如洞察其本质。</li><li><strong>[掌握]</strong>：熟知并能运用；把握；控制。例如掌握自己的命运。</li><li><strong>[了解]</strong>：知道；知道得很清楚；调查；询问。例如据我了解，……</li></ol></li><li><strong>31、意识 认识 领悟 体验</strong><ol><li><strong>[意识]</strong>：觉察，感觉。</li><li><strong>[认识]</strong>：相识，认得；懂得；人脑对客观世界的反映。包括感性认识和理性认识。</li><li><strong>[领悟]</strong>：理解领会。</li><li><strong>[体验]</strong>：<code>名词</code>亲自处于某种环境中而产生的认识。</li></ol></li><li><strong>32、束缚 限制 制约</strong><ol><li><strong>[束缚]</strong>：捆绑，指约束限制。</li><li><strong>[限制]</strong>：不让超过的界限；局限在范围内。</li><li><strong>[制约]</strong>：一事物的存在、变化是另一事物存在变化的先决条件，则前者制约后者。<code>搭配：制约……的发展</code></li></ol></li><li><strong>33、体味 体会 体验</strong><ol><li><strong>[体味]</strong>：体验寻味，如细细体味诗句意境。</li><li><strong>[体会]</strong>：体验领会。</li><li><strong>[体验]</strong>：<code>动词</code>在实践中认识事物；亲身经历；体察；考察。</li></ol></li><li><strong>34、克服 克制 抑制</strong><ol><li><strong>[克服]</strong>：用意志力和力量去战胜；制伏。<code>适用对象为不力条件或消极现象。常 见搭配：克服困难</code></li><li><strong>[克制]</strong>：控制；抑制。<code>强调自我，常见搭配：克制感情</code></li><li><strong>[抑制]</strong>：约束，压制。<code>在某种压力下采取干预措施，搭配：抑制通货膨胀、抑制活性、抑制生长、抑制需求</code></li></ol></li><li><strong>35、遏制 遏止 阻止 阻遏</strong><ol><li><strong>[遏制]</strong>：阻止，禁绝。<code>强调禁绝</code></li><li><strong>[遏止]</strong>：制止。<code>强调控制、停下来</code></li><li><strong>[阻止]</strong>：阻拦制止。<code>强调阻拦，不让发生</code></li><li><strong>[阻遏]</strong>：阻止；遏止，不让其得逞。<code>强调不让得逞</code></li></ol></li><li><strong>36、苛刻 复杂</strong><ol><li><strong>[苛刻]</strong>：条件、要求过高，过于严厉。</li><li><strong>[复杂]</strong>：事物的种类、头绪多而杂。</li></ol></li><li><strong>37、妨害 妨碍</strong><ol><li><strong>[妨害]</strong>：有害于；阻碍；干扰。</li><li><strong>[妨碍]</strong>：使事情不能顺利进行，使过程或进展变得缓慢或困难。</li></ol></li><li><strong>38、秉承 秉持</strong><ol><li><strong>[秉承]</strong>：指接受；承接；按命令/指示办事/处理问题，秉承旨意。</li><li><strong>[秉持]</strong>：执持；持有具有；指操守；内心。如秉持公心，秉持某原则。</li></ol></li><li><strong>39、真切 真实 真观 具体 明确</strong><ol><li><strong>[真切]</strong>：清晰确实。<code>强调清晰，例：雾里看花往往看不真切</code></li><li><strong>[真实]</strong>：与事实相符。<code>强调事实，例：本影片根据真实故事改编</code></li><li><strong>[真观]</strong>：用感情直接接受的或直接观察的。<code>强调直接性</code></li><li><strong>[具体]</strong>：不抽象，不笼统，细节很明确。<code>强调明确，例：制定具体的方案</code></li><li><strong>[明确]</strong>：清晰明白；指概念表达得很明了清楚，使读者或听者不用思索便懂；使清晰、明白而肯定不移。<code>强调清晰明白易懂不含糊，如明确要求</code></li></ol></li><li><strong>40、约束 制衡</strong><ol><li><strong>[约束]</strong>：加以限制，管束。比如约束自己的行为</li><li><strong>[制衡]</strong>：相互制约使平衡。比如董事会和经理分权制衡</li></ol></li><li><strong>41、平均 平衡</strong><ol><li><strong>[平均]</strong>：均与，没有轻重或多少之别。<code>侧重无分别</code></li><li><strong>[平衡]</strong>：对立的各方面在数量或质量上相等或相抵；倾向于保持稳定的情况。<code>侧重稳定状态</code></li></ol></li><li><strong>42、认同 认可 认识 认知</strong><ol><li><strong>[认同]</strong>：认可赞同；承认同一。<code>观点上的赞同，搭配：文化认同、民族认同</code></li><li><strong>[认可]</strong>：承认，许可。<code>态度上的支持</code></li><li><strong>[认识]</strong>：确定某物；知晓，认明。<code>理性上的确定</code></li><li><strong>[认知]</strong>：认识、思维或知觉的自身发展，包括理解和推理的意识官能或过程，靠它获得关于感觉或理念的知识。<code>通过自身获得知识，增进了解的过程，搭配：认识水平、自我认知</code></li></ol></li><li><strong>43、激励 希冀 慰勉 鼓动</strong><ol><li><strong>[激励]</strong>：激发勉励，使振作。<code>为了振作</code></li><li><strong>[激发]</strong>：激动奋发。<code>搭配：激发活力、激发积极性、激发创造力</code></li><li><strong>[希冀]</strong>：希望得到。<code>为了得到</code></li><li><strong>[慰勉]</strong>：抚慰勉励。<code>为了抚慰</code></li><li><strong>[鼓动]</strong>：以言语或行为激励他人使有所行动；唆使。</li></ol></li><li><strong>44、成就 成果 造就</strong><ol><li><strong>[成就]</strong>：业绩，事业上的优良的成效<code>如科学成就</code>；成功，完成；造就，成全。<code>侧重于个人或团队在某个领域内取得的成功或是积极成果</code></li><li><strong>[成果]</strong>：指学习、工作、劳动上的成效和成绩。<code>侧重于完成任务或目标得到的实际的可量化的具体结果</code></li><li><strong>[造就]</strong>：<code>动词</code>培育练就；<code>名词</code>成果，成绩。</li></ol></li><li><strong>45、反映 暴露 折射</strong><ol><li><strong>[反映]</strong>：比喻表现出客观事物的本质。<code>强调真实、客观</code></li><li><strong>[暴露]</strong>：显露 <code>隐蔽的事物、缺陷、矛盾、问题等</code>。<code>强调对事物真相的揭示和公开</code></li><li><strong>[折射]</strong>：比喻通过某种方式反映出事物的表象或实质来。<code>强调对事物的变化和转变，多是思想上、观点上、情感上、品质上的</code></li></ol></li><li><strong>46、转换 转化</strong><ol><li><strong>[转换]</strong>：改变；改换。<code>形式上变化</code></li><li><strong>[转化]</strong>：转变；矛盾的双方经过斗争，在一定条件下，各自向着和自己相反的方面转变，向着对立方面所处的地位转变。<code>性质上的变化</code></li></ol></li><li><strong>47、治理 管理</strong><ol><li><strong>[治理]</strong>：整治调理；整修；改造。<code>侧重于整治，适用范围狭窄</code></li><li><strong>[管理]</strong>：主持或负责某项工作；经管，料理；约束；照管。<code>侧重于经管负责，适用范围更广</code></li></ol></li><li><strong>48、简单 机械 枯燥</strong><ol><li><strong>[简单]</strong>：不复杂；头绪少。<code>头绪少</code></li><li><strong>[机械]</strong>：比喻拘泥于成规，刻板而不知变通。<code>刻板</code></li><li><strong>[枯燥]</strong>：单调，无趣味。<code>单调</code></li></ol></li><li><strong>49、把握 掌握</strong><ol><li><strong>[把握]</strong>：思想上掌握，理解<code>把握文章脉络</code>；抓住<code>如把握机会</code>；成功的根据或信心<code>如有把握</code>。</li><li><strong>[掌握]</strong>：熟知并能运用；控制。<code>如掌握了学习方法</code></li></ol></li><li><strong>50、炮制 创造</strong><ol><li><strong>[炮制]</strong>：泛指编制；制定<code>贬义</code>；制作<code>如法炮制</code>。</li><li><strong>[创造]</strong>：首先想出或做出<code>前所未有的事物</code>。</li></ol></li><li><strong>51、提升 提高 强化</strong><ol><li><strong>[提升]</strong>：使位置、程度、水平、数量、质量等方面比原来高。<code>搭配：提升形象、提升幸福指数、提升工作水平、项目提升改造、提升巩固</code></li><li><strong>[提高]</strong>：指使位置、水平等方面比原来高。<code>搭配：提高效率、提高素质、提高影响力</code></li><li><strong>[强化]</strong>：增强，加强。<code>搭配：强化责任担当、强化工作目标落实、强化……观念、强化……建设、强化工作能力、强化培训等，词义比“加强”重。</code></li></ol></li><li><strong>52、创新 革新 创造</strong><ol><li><strong>[创新]</strong>：抛弃旧的，创造新的。<code>弃旧从新，搭配：科技创新、理论创新、制度创新等</code></li><li><strong>[革新]</strong>：革除旧的，创造新的。<code>搭配：技术革新、设备革新</code></li><li><strong>[创造]</strong>：首先想出或做出前所未有的事物<code>从无到有的过程</code></li></ol></li><li><strong>53、基础 根本 前提 支撑</strong><ol><li><strong>[基础]</strong>：事物发展的根本或起点。</li><li><strong>[根本]</strong>：比喻事物的本源、根基；基础或本质；完全<code>如我根本就不赞成你的主张</code>；简直；从来<code>如他根本没把她当人看</code>；彻底<code>如必须根本改变这里的落后面貌</code>。</li><li><strong>[前提]</strong>：推理中可以推导出一个判断的成立；事物的先决因素。</li><li><strong>[支撑]</strong>：顶住物体使不倒塌；支持局面使不崩溃；抵挡；勉强维持。</li></ol></li><li><strong>54、凝聚 凝结</strong><ol><li><strong>[凝聚]</strong>：集中。<code>适用对象：力量、智慧、民心民意等</code></li><li><strong>[凝结]</strong>：聚集。<code>适用对象：感情、思想、劳动、汗水、记忆等</code></li></ol></li><li><strong>55、培养 培育</strong><ol><li><strong>[培养]</strong>：以适宜的条件促使其发生、成长和繁殖。</li><li><strong>[培育]</strong>： 使某种感情得到发展；培养教育。</li></ol></li><li><strong>56、源泉 根基</strong><ol><li><strong>[源泉]</strong>：水源，比喻事物的根源。<code>强调本源，出处</code></li><li><strong>[根基]</strong>：基础；家底。`强调根本</li></ol></li><li><strong>57、批判 批评 批驳</strong><ol><li><strong>[批判]</strong>：评论；对于是非的判断；对被认为是错误的思想或言行批驳否定。<code>侧重是非判断</code></li><li><strong>[批评]</strong>：评论，批判；对缺点错误提出意见。<code>侧重评论、提意见</code></li><li><strong>[批驳]</strong>：批判驳斥。<code>侧重驳斥、斥责</code></li></ol></li><li><strong>58、演化 演进 演变 变迁</strong><ol><li><strong>[演化]</strong>：群落的逐渐进化；推广教化；推演变化。<code>侧重推演</code></li><li><strong>[演进]</strong>：逐渐地进化。强调某种事物在发展变化中的正向作用。<code>侧重正向变化</code></li><li><strong>[演变]</strong>：变化发展。<code>侧重变化</code></li><li><strong>[变迁]</strong>：事物的变化转移。<code>侧重迁移、转移</code></li></ol></li><li><strong>59、解释 诠释 阐释</strong><ol><li><strong>[解释]</strong>：分析说明。<code>侧重分析</code></li><li><strong>[诠释]</strong>：解说；解释；阐明。<code>侧重讲解、证明</code></li><li><strong>[阐释]</strong>：阐明陈述并解释。<code>侧重陈述</code></li></ol></li><li><strong>60、揭示 揭露 昭示</strong><ol><li><strong>[揭示]</strong>：向人指出不易看清的事理；公布；宣布。<code>搭配：揭示规律、真理、特 性等，多用于研究和哲学领域</code></li><li><strong>[揭露]</strong>：揭发隐蔽的事，使之暴露。<code>多用于负面事件，如揭露罪行</code></li><li><strong>[昭示]</strong>：明白地表示或宣布。</li></ol></li><li><strong>61、改进 改善</strong><ol><li><strong>[改进]</strong>：改变原有状况，使得到提高；提高价值或质量使之更有利可图、更优良、 更受人欢迎。<code>侧重于工作方面的提高。搭配：改进工艺、改进作风、改进工作</code></li><li><strong>[改善]</strong>：使原来的状况变得好些；部分地、在某种程度上提到较好、较高水平。 <code>侧重于程度上变得更好。搭配：改善条件、改善水平、改善环境</code></li></ol></li><li><strong>62、停滞 停止</strong><ol><li><strong>[停滞]</strong>：受到阻碍，不能顺利地进行或发展。<code>因某种原因使得发展或进行受阻， 有内在原因</code></li><li><strong>[停止]</strong>：停下来，不再进行。<code>停下，本身不含原因</code></li></ol></li><li><strong>63、湮灭 泯灭</strong><ol><li><strong>[湮灭]</strong>：埋没；磨灭。</li><li><strong>[泯灭]</strong>：消灭；消失；<code>形迹、印象等</code>消灭。<code>如永不泯灭的信仰</code></li></ol></li><li><strong>64、固化 异化</strong><ol><li><strong>[固化]</strong>：指对事物的形成某种固定看法、观点的过程。<code>强调固定</code></li><li><strong>[异化]</strong>：同类事物演变成不同类的。<code>强调变得不同，反义词为“同化”</code></li></ol></li><li><strong>65、汇集 会集</strong><ol><li><strong>[会集]</strong>：集合。</li><li><strong>[汇集]</strong>：累积。</li></ol></li><li><strong>66、检验 验证</strong><ol><li><strong>[检验]</strong>：检查并验证。<code>侧重于检查是否合格达标</code></li><li><strong>[验证]</strong>：经过检验得到证实。<code>侧重于证实精确性或准确性、有效性</code></li></ol></li><li><strong>67、污蔑 诬蔑</strong><ol><li><strong>[污蔑]</strong>：歪曲事实，造谣诽谤，败坏他人名誉。主要是用话语栽赃陷害。污，使 不再纯洁。<code>脏东西，抹黑，手段卑鄙</code></li><li><strong>[诬蔑]</strong>：造谣损毁他人的名誉或名节。<code>无中生有，人身攻击</code></li></ol></li><li><strong>68、机警 警惕 警觉</strong><ol><li><strong>[机警]</strong>：对情况的变化觉察得快；机智敏锐。</li><li><strong>[警惕]</strong>：对可能发生的危险情况或错误倾向保持敏锐的感觉。</li><li><strong>[警觉]</strong>：对危险或情况变化的敏锐感觉。</li></ol></li><li><strong>69、遴选 甄选 挑选 筛选</strong><ol><li><strong>[遴选]</strong>：选拔<code>要求比较严格</code>，比如人才的遴选，大熊猫的遴选。</li><li><strong>[甄选]</strong>：甄别选择。</li><li><strong>[挑选]</strong>：从若干人或事物中找出适合要求的。</li><li><strong>[筛选]</strong>：指作物或树木选种的方法；泛指在同类事物中去掉不需要的，留下需要的。</li></ol></li><li><strong>70、探索 探求 探究 钻研 研究 考究</strong><ol><li><strong>[探索]</strong>：探寻求索。</li><li><strong>[探求]</strong>：探索寻求。</li><li><strong>[探究]</strong>：探索研究。</li><li><strong>[钻研]</strong>：深入细致地研究，如钻研学术，刻苦钻研的精神。</li><li><strong>[研究]</strong>：钻研，探求事物的性质、规律等；考虑，商讨，如经研究决定，……</li></ol></li><li><strong>71、向导 指导 指南 指引 引领</strong><ol><li><strong>[向导]</strong>：领路人，导游。<code>侧重引路</code></li><li><strong>[指导]</strong>：指示教导；指点引导。<code>侧重教学示范</code></li><li><strong>[指南]</strong>：为人们提供指导性资料或情况的东西<code>如旅游指南、操作手册</code>；比喻辩别 方向的依据<code>侧重提供某种依据，如指南针</code>。</li><li><strong>[指引]</strong>：指示，引导。<code>侧重向前进，例：指引人们向前进</code></li><li><strong>[引领]</strong>：指带动事物跟随他或他们向某一方向运动、发展。<code>侧重预期方向性， 例：引领时尚潮流</code></li></ol></li><li><strong>72、拓展 扩展 扩充</strong><ol><li><strong>[拓展]</strong>：开拓、扩展。<code>功能和空间上</code></li><li><strong>[扩展]</strong>：向外伸展；扩展对外贸易。<code>空间上</code></li><li><strong>[扩充]</strong>：扩大充实，使增多。<code>数量上</code></li></ol></li><li><strong>73、遵守 恪守 遵从 遵循</strong><ol><li><strong>[遵守]</strong>：依照规定做；不违背。<code>适用对象为制度层面，常见搭配：遵守纪律、遵守规则、遵守诺言</code></li><li><strong>[恪守]</strong>：谨慎而恭顺地遵守。<code>适用对象为传统层面，常见搭配：恪守孝道、恪守本分</code></li><li><strong>[遵从]</strong>：遵照并依从<code>如遵从老师的教导</code>；遵照正式或官方的规定<code>如遵从全国人民的意愿</code>。</li><li><strong>[遵循]</strong>：遵从，依照。<code>搭配：遵循规律、遵循某理念、根本遵循</code></li></ol></li><li><strong>74、窘境 困境 窘迫 尴尬</strong><ol><li><strong>[窘境]</strong>：使人为难、害羞或难堪，尤指因缺钱用或无钱还债而造成的困境；令人不知如何是好的事情。<code>没钱还债没钱用</code></li><li><strong>[困境]</strong>：形容一件事进入一个难办的地步。<code>事情难办</code></li><li><strong>[窘迫]</strong>：使苦恼或窘迫；尤指使经济困难；处境困急。<code>生活经济困难</code></li><li><strong>[尴尬]</strong>：处于两难境地无法摆脱；行为、态度不正常的。<code>无法摆脱的局面</code></li></ol></li><li><strong>75、捏造 虚构 杜撰</strong><ol><li><strong>[捏造]</strong>：凭空编造。</li><li><strong>[虚构]</strong>：凭想象编造出来。<code>如本故事纯属虚构</code></li><li><strong>[杜撰]</strong>：臆造；虚构，毫无根据。</li></ol></li><li><strong>76、败坏 破坏 损坏 损害</strong><ol><li><strong>[败坏]</strong>：损坏，破坏<code>如败坏社会风气，败坏门庭</code>；行为不符合社会准则<code>如道德败坏</code>。<code>适用对象：抽象事物</code></li><li><strong>[破坏]</strong>：摧毁；毁坏<code>如破坏城池</code>；使受到损害<code>如破坏名誉</code>；变革；破除；违反<code>如破坏纪律</code>。<code>适用对象：具体或抽象均可</code></li><li><strong>[损坏]</strong>：由于各种原因造成的物件残破使之失去部分。<code>如不要损坏公共财物``适用对象：具体的物品物件</code></li><li><strong>[损害]</strong>：使受伤害；使受损失。</li></ol></li><li><strong>77、沉溺 沉迷</strong><ol><li><strong>[沉溺]</strong>：无节制地沉湎或放纵。<code>例：沉溺虚名者，是当局者迷的。</code></li><li><strong>[沉迷]</strong>：深深地迷惑或迷恋某事物。<code>他们两个都沉迷于看 NBA 篮球赛。词义轻重：沉迷﹤沉溺</code></li></ol></li><li><strong>78、.渗透 辐射 扩散 传播</strong><ol><li><strong>[渗透]</strong>：比喻某种事物或势力逐渐进入其他方面</li><li><strong>[辐射]</strong>：从中心向各个方向沿着直线伸展出去；对周边事物产生的一定影响。</li><li><strong>[扩散]</strong>：向外扩展分散；到新的部位再生长。</li><li><strong>[传播]</strong>：传送或散布<code>如传播知识</code>；传染<code>如疾病的传播</code>；广泛地散布；使普遍知道<code>如传播关于最新科学发明的情报</code>。</li></ol></li><li><strong>79、映射 映衬 映照 反映</strong><ol><li><strong>[映射]</strong>：意思是映照、照射，也可以指反射反映。<code>侧重于反射</code></li><li><strong>[映衬]</strong>：互相映照、衬托使显现。<code>侧重于衬托</code></li><li><strong>[映照]</strong>：照射、呼应。<code>侧重于呼应</code></li><li><strong>[反映]</strong>：反照。比喻表现出客观事物的本质。<code>侧重于表现</code></li></ol></li><li><strong>80、衰落 式微 凋敝</strong><ol><li><strong>[衰落]</strong>：由兴盛转向没落；由强大转为弱小。<code>强调事物由盛转衰的渐进过程，衰落的因素是多方面的，适用对象：国家、组织、产业或个人</code></li><li><strong>[式微]</strong>：衰落；衰微。<code>强调事物的质量、地位或声誉的下降，适用对象：国家、组织、产业或个人</code></li><li><strong>[凋敝]</strong>：用来描述自然界中生物或植物的衰亡过程。<code>强调事物衰弱和衰败的状态</code></li></ol></li><li><strong>81、修正 修改 改正</strong><ol><li><strong>[修正]</strong>：改正，修改使正确。<code>侧重于改的目的，比如云南天文台通过潮汐作用修正恒星年龄</code></li><li><strong>[修改]</strong>：改动、删节或增添；改正，纠正。<code>侧重于改的动作，比如修改文字颜色和底色</code></li><li><strong>[改正]</strong>：纠正错误。<code>侧重纠错，比如这5个坏习惯快改正</code></li></ol></li><li><strong>82、考量 考验 权衡</strong><ol><li><strong>[考量]</strong>：考查衡量；考虑商量；思量。<code>偏重考虑</code></li><li><strong>[权衡]</strong>：评量；比较。<code>偏重平衡取舍</code></li><li><strong>[考验]</strong>：考查验证。<code>偏重验证、测试</code></li></ol></li><li><strong>83、考察 考查</strong><ol><li><strong>[考察]</strong>：实地观察调查。<code>侧重察看调研，比如卫辉市考察团莅淅考察绿化工作</code></li><li><strong>[考查]</strong>：考较查验。<code>侧重测验评价，比如考查汉语能力测试</code></li></ol></li><li><strong>84、冲突 矛盾 隔阂</strong><ol><li><strong>[冲突]</strong>：对立的、互不相容的力量或性质<code>如观念、利益、意志</code>的互相干扰<code>如革命与旧势力相冲突</code>；以争吵、摩擦和对立为特色的持久的不和<code>如儿子与继母之间常有冲突</code>；意见不合，发生争执<code>如过去的挫折，和偶然的冲突仍然可能在他与她之间发生</code>。<code>强调摩擦、争执，包含言语及肢体动作</code></li><li><strong>[矛盾]</strong>：矛盾是在两个或更多陈述、想法或行动之间的不一致，无善恶之分。<code>强调言语、行动的逻辑不统一</code></li><li><strong>[隔阂]</strong>：情意不相通，彼此思想有距离。<code>强调感情沟通上的距离，有代沟。固定搭配：消除隔阂。</code></li></ol></li><li><strong>85、变革 改革 改变 变动</strong><ol><li><strong>[变革]</strong>：指的是改变事物的本质。</li><li><strong>[改革]</strong>：指的是把事物中旧的不合理的部分改成新的、能适应客观情况的。<code>比如金融体制改革，改革开放，党和国家机构改革</code></li><li><strong>[改变]</strong>：指的是事物发生显著的差别。</li><li><strong>[变动]</strong>：变化<code>多指社会现象，如人事变动</code></li></ol></li><li><strong>86、表扬 表彰 奖励 赞扬</strong><ol><li><strong>[表扬]</strong>：公开赞美，使大家知道。</li><li><strong>[表彰]</strong>：较为正式严肃场合的使用。</li><li><strong>[奖励]</strong>：给予荣誉或财物来鼓励。</li><li><strong>[赞扬]</strong>：称赞表扬。</li></ol></li><li><strong>87、感悟 领悟 领会</strong><ol><li><strong>[感悟]</strong>：有所感触而醒悟或领悟。比如有效性，是在实践中思考和感悟的。<code>有所感</code></li><li><strong>[领悟]</strong>：体会，解悟。比如从他们的记录中我能领悟到某些哲理。<code>有所明白</code></li><li><strong>[领会]</strong>：了解、认识事物并有所体会。比如领会文件精神。<code>深入思考并有所体悟</code></li></ol></li><li><strong>88、注脚 见证 记载</strong><ol><li><strong>[注脚]</strong>：泛指解释、说明。<code>侧重说明作用</code></li><li><strong>[见证]</strong>：指证人或证物。<code>侧重证明作用</code></li><li><strong>[记载]</strong>：把事情记录下来；记录事情的文字。<code>侧重记录作用</code></li></ol></li><li><strong>89、效仿 膜拜 尊崇 青睐 垂青</strong><ol><li><strong>[效仿]</strong>：学着做。<code>适用范围较广，单纯地从动作上模仿，未有心理上的态度</code></li><li><strong>[膜拜]</strong>：合掌加额，长跪而拜。表示尊敬或畏服的礼式。<code>极端恭敬或敬畏，动作和心理上态度兼具且程度极深，搭配：顶礼膜拜</code></li><li><strong>[尊崇]</strong>：敬重推崇，乃至崇拜。<code>侧重于敬重、崇敬的心理态度</code></li><li><strong>[青睐]</strong>：指喜爱或重视；受尊重；受欢迎。<code>侧重于人或事物受欢迎，受重视</code></li><li><strong>[垂青]</strong>：比喻得到重视，受到优待</li></ol></li><li><strong>90、防范 戒备 预防</strong><ol><li><strong>[防范]</strong>：戒备；防备，也比喻约束物。<code>强调的是避免利益受损失。搭配：严加 防范；防范电信网络诈骗</code></li><li><strong>[戒备]</strong>：警惕防备以应不测。<code>强调保持警惕或警戒状态。搭配：戒备森严</code></li><li><strong>[预防]</strong>：预先做好防备。<code>强调避免可能预见的情况发生。如，天气转凉，预防 感冒</code></li></ol></li><li><strong>91、潜藏 蕴藏 隐藏</strong><ol><li><strong>[潜藏]</strong>：藏在隐蔽处；隐藏在显露的外表之下。<code>侧重于潜在</code></li><li><strong>[蕴藏]</strong>：积存。<code>侧重于积累存在</code></li><li><strong>[隐藏]</strong>：隐蔽躲藏，不让别人发现。<code>侧重于隐蔽</code></li></ol></li><li><strong>92、保管 保存 储存 收藏 储藏</strong><ol><li><strong>[保管]</strong>：收藏和管理，照管。<code>侧重管理，如保管图书</code></li><li><strong>[保存]</strong>：继续存在，不受损失；保管收存。<code>侧重存的动作</code></li><li><strong>[储存]</strong>：把<strong>[钱或物]</strong>存放起来暂时不用；大量积累。<code>侧重量的积累，如储存剩余小麦的谷物仓库</code></li><li><strong>[收藏]</strong>：收集保藏；收起来保存；珍宝等。<code>侧重收集</code></li><li><strong>[储藏]</strong>：贮藏，收藏；保藏；把…积聚收藏起来。<code>侧重存放，如储藏粮食</code></li></ol></li><li><strong>93、安置 安顿 安排 安放</strong><ol><li><strong>[安置]</strong>：使人或事物有着落。如安置灾民，安置家属。<code>着重于“置”，使各得其所</code></li><li><strong>[安顿]</strong>：使人或事物有着落；安排妥当。如妈妈把孩子安顿在托儿所里。<code>着重于“顿”，妥当安排使有着落</code></li><li><strong>[安排]</strong>： 有条理、分先后地处理事物， 安置人员。如安排劳动力。<code>着重于“排”，分轻重缓急，先后主次，多指人事、任务的处理</code></li><li><strong>[安放]</strong>：使物件处于一定的位置。如无处安放的灵魂。<code>着重于“放”，多指把物件放在合适的位置上</code></li></ol></li><li><strong>94、消弭 对冲 消除</strong><ol><li><strong>[消弭]</strong>：意思是清除、消除某些不好的事情。</li><li><strong>[对冲]</strong>：对冲是指特意减低另一项投资风险的投资，因此它是一种投资行为，通常用于减低商业风险的同时保证自己在投资中获利。</li><li><strong>[消除]</strong>：使不存在；除去。<code>搭配：消除隔阂、消除矛盾、消除某种现象</code></li></ol></li><li><strong>95、勾勒 描绘 叙写 擘画 渲染 憧憬</strong><ol><li><strong>[勾勒]</strong>：用线条描画出轮廓或者用简练的文笔叙述大概情况。<code>偏大概，轮廓</code></li><li><strong>[描绘]</strong>：画出，描画。<code>偏形象化</code></li><li><strong>[叙写]</strong>：叙述描写。<code>偏具体细节，注重连贯性</code></li><li><strong>[擘画]</strong>：谋划，经营。筹划，安排。<code>如擘画蓝图，擘画将来</code></li><li><strong>[渲染]</strong>：比喻夸大的形容。<code>如渲染战争恐怖</code></li><li><strong>[憧憬]</strong>：向往。</li></ol></li><li><strong>96、遗漏 忽视 丢失 轻视 漠视 无视</strong><ol><li><strong>[遗漏]</strong>：因疏忽而漏掉。</li><li><strong>[忽视]</strong>：不重视。<code>用法：……不容忽视；忽视了……</code></li><li><strong>[丢失]</strong>：失掉；遗失。</li><li><strong>[轻视]</strong>：小看或讨厌；不认真对待。</li><li><strong>[漠视]</strong>：冷淡地对待；不放在心上；藐视，轻视。<code>词义比无视轻，侧重于态度冷淡，不长心。搭配：漠视安危、漠视利益需求、漠视人权</code></li><li><strong>[无视]</strong>：不放在眼里，根本不考虑。<code>词义程度比漠视重</code></li></ol></li><li><strong>97、镌刻 铭刻 铭记</strong><ol><li><strong>[镌刻]</strong>：雕刻的意思。</li><li><strong>[铭刻]</strong>：刻在器物上的文字；铭记；牢记在心，无法忘记。</li><li><strong>[铭记]</strong>：牢记在心中；时刻铭记。<code>例：铭记历史；让我们铭记道德的苍穹长又长，但它终将落向正义。</code></li></ol></li><li><strong>98、把持 控制 操纵</strong><ol><li><strong>[把持]</strong>：独占位置、权力等，不让别人参与<code>含贬义</code>。<code>强调具体占据某个位 置或某种权力，比如把持朝政</code></li><li><strong>[控制]</strong>：掌握住不使任意活动或越出范围。<code>强调在一定范围内有某种权力或势 力，不一定具体掌权</code></li><li><strong>[操纵]</strong>：控制或开动机械、仪器等；用不正当手段支配、控制。<code>强调不在某个 位置上、不具体掌权，而在幕后支配</code></li></ol></li><li><strong>99、草率 随意 敷衍</strong><ol><li><strong>[草率]</strong>：形容粗糙简略。</li><li><strong>[随意]</strong>：指任凭自己的意思。</li><li><strong>[敷衍]</strong>：做事不负责或待人不肯切，只做表面上的应付。</li></ol></li><li><strong>100、镶嵌 穿插 点缀</strong><ol><li><strong>[镶嵌]</strong>：以物嵌入，作为装饰。<code>工艺制作术语</code></li><li><strong>[穿插]</strong>：互相错开；交叉。<code>为了增加情节的曲折性和衬托主题</code></li><li><strong>[点缀]</strong>：衬托；装饰；应景；凑数。<code>为了使事物更好看，适用范围较广</code></li></ol></li><li><strong>101、致使 导致</strong><ol><li><strong>[致使]</strong>：导致，由……造成 造句：由于地址没有写清楚，致使信件无法投递。</li><li><strong>[导致]</strong>：使产生，使促成 造句：他的粗枝大叶导致他的失败。</li></ol></li><li><strong>102、契机 时机 机会 机遇</strong><ol><li><strong>[契机]</strong>：机会，转折变化的机缘。通常指事物发展过程中的关键、枢纽或决定性的环节。<code>强调的是关键的转折点。搭配：以……为契机；抓住……的契机</code></li><li><strong>[时机]</strong>：具有时间性的客观条件；机会。<code>强调选择合适的时间。搭配：把握时机；时机成熟</code></li><li><strong>[机会]</strong>：具有时间性的有利情况；时机；关键；要害。<code>客观存在的条件。搭配：抓住机会；珍惜机会</code></li><li><strong>[机遇]</strong>：机会；有利的境遇。<code>客观存在的主观判断。搭配：历史性机遇；机遇与挑战并存</code></li></ol></li><li><strong>102、哀怜 爱怜 爱恋</strong><ol><li><strong>[哀怜]</strong>：指对别人的不幸遭遇表示同情，如“中华民族有哀怜弱者的传统”。</li><li><strong>[爱怜]</strong>：指十分疼爱，多用于子女，如“爱怜子女”。</li><li><strong>[爱恋]</strong>：指热爱而难以分离，多用于男女之间，如“二十多年来，他俩一直相互爱恋着”。</li></ol></li></ol>',4)])])}const h=l(s,[["render",i]]);export{_ as __pageData,h as default};
